def _now_ms() -> int:
    return int(time.time() * 1000)


def _windows_trim_process_working_set() -> bool:
    if not sys.platform.startswith("win"):
        return False
    try:
        kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)
        psapi = ctypes.WinDLL("psapi", use_last_error=True)
        kernel32.GetCurrentProcess.restype = ctypes.c_void_p
        handle = kernel32.GetCurrentProcess()
        if not handle:
            return False
        psapi.EmptyWorkingSet.argtypes = [ctypes.c_void_p]
        psapi.EmptyWorkingSet.restype = ctypes.c_int
        return bool(psapi.EmptyWorkingSet(handle))
    except Exception:
        return False


def _reply_similarity_key(value: Any) -> str:
    text = str(value or "").lower()
    return re.sub(r"[\s\W_]+", "", text, flags=re.UNICODE)


def _text_similarity_ratio(left: str, right: str) -> float:
    left_key = _reply_similarity_key(left)
    right_key = _reply_similarity_key(right)
    if not left_key or not right_key:
        return 0.0
    shorter, longer = (left_key, right_key) if len(left_key) <= len(right_key) else (right_key, left_key)
    containment = 1.0 if len(shorter) >= 14 and shorter in longer else 0.0
    return max(containment, difflib.SequenceMatcher(None, left_key, right_key).ratio())


def _looks_like_redundant_reply(candidate: str, previous: list[dict[str, Any]]) -> bool:
    key = _reply_similarity_key(candidate)
    if len(key) < 8:
        return False
    for item in previous[-3:]:
        old_key = _reply_similarity_key(item.get("text") if isinstance(item, dict) else "")
        if len(old_key) < 8:
            continue
        if _text_similarity_ratio(key, old_key) >= 0.74:
            return True
    return False


def _looks_like_repeated_thought(candidate: str, previous: list[dict[str, Any]]) -> bool:
    key = _reply_similarity_key(candidate)
    if len(key) < 14:
        return False
    for item in previous[-3:]:
        old_text = str(item.get("text") if isinstance(item, dict) else "")
        if _text_similarity_ratio(key, old_text) >= 0.78:
            return True
    return False


def _append_quality_flag(payload: dict[str, Any], flag: str) -> None:
    flags = payload.get("quality_flags")
    if not isinstance(flags, list):
        flags = []
    if flag not in flags:
        flags.append(flag)
    payload["quality_flags"] = flags


def _prompt_section_row(label: str, content: Any) -> dict[str, Any]:
    text = str(content or "")
    return {
        "label": label,
        "chars": len(text),
        "estimated_tokens": int(math.ceil(len(text) / 1.8)) if text else 0,
    }


def _prompt_section_rows_with_total(prefix: str, sections: list[tuple[str, str]]) -> tuple[list[dict[str, Any]], int, int]:
    rows: list[dict[str, Any]] = []
    total_chars = 0
    total_tokens = 0
    for label, content in sections:
        row = _prompt_section_row(f"{prefix}:{label}", content)
        rows.append(row)
        total_chars += int(row.get("chars", 0) or 0)
        total_tokens += int(row.get("estimated_tokens", 0) or 0)
    return rows, total_chars, total_tokens


def _prompt_budget_status(prompt_chars: int = 0, estimated_tokens: int = 0) -> str:
    tokens = max(0, int(estimated_tokens or 0))
    if tokens <= 0 and prompt_chars:
        tokens = int(math.ceil(max(0, int(prompt_chars or 0)) / 1.8))
    if tokens >= _PROMPT_BUDGET_FAIL_TOKENS:
        return "fail"
    if tokens >= _PROMPT_BUDGET_WARN_TOKENS:
        return "warn"
    return "pass"


