def _detect_image_bytes(data: bytes) -> dict[str, Any]:
    raw = data if isinstance(data, (bytes, bytearray)) else b""
    signatures: list[tuple[str, str, bytes]] = [
        ("png", "image/png", b"\x89PNG\r\n\x1a\n"),
        ("jpg", "image/jpeg", b"\xff\xd8\xff"),
        ("gif", "image/gif", b"GIF87a"),
        ("gif", "image/gif", b"GIF89a"),
        ("webp", "image/webp", b"RIFF"),
    ]
    for ext, mime, sig in signatures:
        if raw.startswith(sig) and (ext != "webp" or raw[8:12] == b"WEBP"):
            return {"ok": True, "ext": ext, "mime_type": mime, "offset": 0, "bytes": bytes(raw)}
    max_scan = min(len(raw), 4096)
    for offset in range(1, max_scan):
        tail = raw[offset:]
        for ext, mime, sig in signatures:
            if tail.startswith(sig) and (ext != "webp" or tail[8:12] == b"WEBP"):
                return {"ok": True, "ext": ext, "mime_type": mime, "offset": offset, "bytes": bytes(tail)}
    return {"ok": False, "reason": "image_signature_not_found", "size": len(raw), "head_hex": bytes(raw[:32]).hex()}


def _validate_png_bytes(data: bytes) -> dict[str, Any]:
    raw = bytes(data or b"")
    if not raw.startswith(b"\x89PNG\r\n\x1a\n"):
        return {"ok": False, "reason": "image_png_signature_missing"}
    pos = 8
    seen_ihdr = False
    seen_iend = False
    idat_parts: list[bytes] = []
    while pos + 8 <= len(raw):
        length = int.from_bytes(raw[pos : pos + 4], "big")
        chunk_type = raw[pos + 4 : pos + 8]
        pos += 8
        if length < 0 or pos + length + 4 > len(raw):
            return {"ok": False, "reason": "image_png_chunk_truncated", "chunk": chunk_type.decode("ascii", errors="replace")}
        chunk_data = raw[pos : pos + length]
        expected_crc = int.from_bytes(raw[pos + length : pos + length + 4], "big")
        actual_crc = zlib.crc32(chunk_type)
        actual_crc = zlib.crc32(chunk_data, actual_crc) & 0xFFFFFFFF
        if actual_crc != expected_crc:
            return {
                "ok": False,
                "reason": "image_png_crc_invalid",
                "chunk": chunk_type.decode("ascii", errors="replace"),
                "expected_crc": expected_crc,
                "actual_crc": actual_crc,
            }
        pos += length + 4
        if chunk_type == b"IHDR":
            seen_ihdr = length == 13
        elif chunk_type == b"IDAT":
            idat_parts.append(chunk_data)
        elif chunk_type == b"IEND":
            seen_iend = True
            break
    if not seen_ihdr:
        return {"ok": False, "reason": "image_png_ihdr_missing_or_invalid"}
    if not seen_iend:
        return {"ok": False, "reason": "image_png_iend_missing"}
    if idat_parts:
        try:
            zlib.decompress(b"".join(idat_parts))
        except Exception as exc:
            return {"ok": False, "reason": "image_png_idat_invalid", "error": str(exc)}
    return {"ok": True, "method": "png_chunk_validate"}


def _validate_image_bytes(data: bytes, ext: str = "") -> dict[str, Any]:
    raw = bytes(data or b"")
    if not raw:
        return {"ok": False, "reason": "image_empty_bytes"}
    try:
        from PIL import Image  # type: ignore

        with Image.open(BytesIO(raw)) as image:
            image_format = str(image.format or "").lower()
            width, height = image.size
            image.verify()
        return {"ok": True, "method": "pillow", "format": image_format, "width": width, "height": height}
    except ModuleNotFoundError:
        pass
    except ImportError:
        pass
    except Exception as exc:
        return {"ok": False, "reason": "image_decode_failed", "error": str(exc)}
    ext_key = str(ext or "").lower().lstrip(".")
    if ext_key == "png":
        return _validate_png_bytes(raw)
    if ext_key in {"jpg", "jpeg"} and not raw.endswith(b"\xff\xd9"):
        return {"ok": False, "reason": "image_jpeg_eoi_missing"}
    if ext_key == "gif" and not raw.endswith(b";"):
        return {"ok": False, "reason": "image_gif_trailer_missing"}
    return {"ok": True, "method": "signature_only"}


def _validate_detected_image_bytes(detected: dict[str, Any]) -> dict[str, Any]:
    if not detected.get("ok"):
        return detected
    image_bytes = bytes(detected.get("bytes") or b"")
    validation = _validate_image_bytes(image_bytes, str(detected.get("ext") or ""))
    if not validation.get("ok"):
        return {
            "ok": False,
            "reason": validation.get("reason") or "image_validation_failed",
            "size": len(image_bytes),
            "head_hex": image_bytes[:32].hex(),
            "validation": validation,
            **{key: value for key, value in detected.items() if key not in {"ok", "bytes"}},
        }
    detected["validation"] = validation
    return detected


def _decode_generated_image_b64(value: Any) -> dict[str, Any]:
    text = str(value or "").strip()
    if not text:
        return {"ok": False, "reason": "empty_b64_json"}
    if text.startswith("data:image/") and "," in text:
        text = text.split(",", 1)[1]
    try:
        data = base64.b64decode(text, validate=False)
    except Exception as exc:
        return {"ok": False, "reason": "base64_decode_failed", "error": str(exc)}
    detected = _validate_detected_image_bytes(_detect_image_bytes(data))
    if not detected.get("ok"):
        return detected
    return {"ok": True, **detected, "original_size": len(data)}


