_MAX_JSONL_BYTES = 2 * 1024 * 1024
_MAX_JSONL_ARCHIVES = 3
_MAX_JSON_ROW_CHARS = 24_000
_MAX_STATE_BYTES = 12 * 1024 * 1024
_MAX_SNAPSHOT_BYTES = 4 * 1024 * 1024
_MAX_ASSET_JSON_BYTES = 256 * 1024 * 1024
_CRITICAL_JSON_BACKUP_LIMIT = 12
_OVERSIZED_STATE_BACKUP_LIMIT = 6
_PROMPT_BUDGET_WARN_TOKENS = 100_000
_PROMPT_BUDGET_FAIL_TOKENS = 200_000
_DATA_URL_RE = re.compile(r"data:([a-zA-Z0-9.+-]+/[a-zA-Z0-9.+-]+);base64,([A-Za-z0-9+/=\s_-]{256,})")


def _redact_large_inline_data(value: Any, *, max_string_chars: int = 6000, depth: int = 0) -> Any:
    if depth > 12:
        return "<truncated:depth>"
    if isinstance(value, str):
        text = value
        if text.startswith("data:") and ";base64," in text:
            header, data = text.split(",", 1)
            digest = hashlib.sha256(data[:200000].encode("utf-8", errors="ignore")).hexdigest()[:16]
            return f"{header},<inline_base64_redacted chars={len(data)} sha256={digest}>"
        text = _DATA_URL_RE.sub(
            lambda match: f"data:{match.group(1)};base64,<inline_base64_redacted chars={len(match.group(2))}>",
            text,
        )
        if len(text) > max_string_chars:
            return text[:max_string_chars] + f"...<truncated chars={len(text)}>"
        return text
    if isinstance(value, dict):
        out: dict[str, Any] = {}
        for key, item in value.items():
            key_text = str(key)
            if key_text.lower() in {"data_url", "b64_json", "base64", "image_data", "inline_data"} and isinstance(item, str) and len(item) > 256:
                out[key] = _redact_large_inline_data(item, max_string_chars=max_string_chars, depth=depth + 1)
            else:
                out[key] = _redact_large_inline_data(item, max_string_chars=max_string_chars, depth=depth + 1)
        return out
    if isinstance(value, list):
        limit = 200 if depth < 4 else 80
        rows = [_redact_large_inline_data(item, max_string_chars=max_string_chars, depth=depth + 1) for item in value[:limit]]
        if len(value) > limit:
            rows.append({"truncated_items": len(value) - limit})
        return rows
    return value


def _json_bytes(payload: Any, *, compact: bool = False) -> bytes:
    if compact:
        text = json.dumps(payload, ensure_ascii=False, separators=(",", ":"))
    else:
        text = json.dumps(payload, ensure_ascii=False, indent=2)
    return text.encode("utf-8")


def _safe_write_bytes(path: Path, data: bytes) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp = path.with_name(path.name + ".tmp")
    tmp.write_bytes(data)
    tmp.replace(path)


def _backup_path_for(path: Path, *, suffix: str = ".bak") -> Path:
    return path.with_name(path.name + suffix)


def _timestamped_backup_path_for(path: Path) -> Path:
    timestamp = time.strftime("%Y%m%d-%H%M%S", time.localtime())
    return path.with_name(f"{path.name}.{timestamp}.bak")


def _critical_json_backups(path: Path) -> list[Path]:
    rows: list[Path] = []
    try:
        parent = path.parent
        if parent.exists():
            rows.extend(parent.glob(f"{path.name}*.bak"))
    except Exception:
        pass
    rows = [item for item in rows if item.exists() and item.is_file()]
    rows.sort(key=lambda item: item.stat().st_mtime if item.exists() else 0, reverse=True)
    return rows


def _oversized_state_backups(path: Path) -> list[Path]:
    rows: list[Path] = []
    try:
        parent = path.parent
        if parent.exists():
            rows.extend(parent.glob(f"{path.stem}.oversized.*{path.suffix}"))
    except Exception:
        pass
    rows = [item for item in rows if item.exists() and item.is_file()]
    rows.sort(key=lambda item: item.stat().st_mtime if item.exists() else 0, reverse=True)
    return rows


def _prune_critical_json_backups(path: Path, *, limit: int = _CRITICAL_JSON_BACKUP_LIMIT) -> None:
    backups = _critical_json_backups(path)
    for old in backups[max(0, int(limit)) :]:
        try:
            old.unlink()
        except OSError:
            pass


def _prune_oversized_state_backups(path: Path, *, limit: int = _OVERSIZED_STATE_BACKUP_LIMIT) -> None:
    backups = _oversized_state_backups(path)
    for old in backups[max(0, int(limit)) :]:
        try:
            old.unlink()
        except OSError:
            pass


def _backup_existing_file(path: Path, *, timestamped: bool = False, min_bytes: int = 2) -> Path | None:
    try:
        if not path.exists() or not path.is_file() or path.stat().st_size < max(0, int(min_bytes)):
            return None
        backup = _timestamped_backup_path_for(path) if timestamped else _backup_path_for(path)
        backup.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(path, backup)
        if timestamped:
            _prune_critical_json_backups(path)
        return backup
    except Exception:
        return None


def _rotate_jsonl_if_needed(path: Path, *, max_bytes: int = _MAX_JSONL_BYTES, max_archives: int = _MAX_JSONL_ARCHIVES) -> None:
    try:
        if not path.exists() or path.stat().st_size <= max_bytes:
            return
        timestamp = time.strftime("%Y%m%d-%H%M%S", time.localtime())
        archive = path.with_name(f"{path.stem}.{timestamp}.jsonl.gz")
        with path.open("rb") as src, gzip.open(archive, "wb", compresslevel=5) as dst:
            shutil.copyfileobj(src, dst, length=1024 * 1024)
        path.write_text("", encoding="utf-8")
        archives = sorted(path.parent.glob(f"{path.stem}.*.jsonl.gz"), key=lambda item: item.stat().st_mtime)
        for old in archives[:-max(0, int(max_archives))]:
            try:
                old.unlink()
            except OSError:
                pass
    except Exception:
        return


def _trim_output_files() -> None:
    """Best-effort guardrail: keep runtime outputs bounded for long-running users."""
    root = Path(__file__).resolve().parent / "outputs"
    try:
        if not root.exists():
            return
        now = time.time()
        for path in list(root.glob("cycle_*.json")):
            try:
                if path.stat().st_size > 2 * 1024 * 1024 or now - path.stat().st_mtime > 2 * 24 * 3600:
                    path.unlink()
            except OSError:
                pass
        for path in list(root.rglob("*.jsonl")):
            _rotate_jsonl_if_needed(path)
        for pattern, keep, max_age_days in (
            ("agent/generated_image_reviews/*.json", 80, 14),
            ("agent/generated_images/*", 120, 30),
            ("agent/incoming_attachments/*", 240, 14),
            ("agent/runtime_packages/*.zip", 30, 90),
        ):
            rows = sorted(root.glob(pattern), key=lambda item: item.stat().st_mtime if item.exists() else 0)
            cutoff = now - max_age_days * 24 * 3600
            for item in rows:
                try:
                    if len(rows) > keep or item.stat().st_mtime < cutoff:
                        item.unlink()
                        rows.remove(item)
                except OSError:
                    pass
    except Exception:
        return


def _file_info(path: Path) -> dict[str, Any]:
    try:
        stat = path.stat()
        return {"path": str(path), "exists": True, "bytes": int(stat.st_size), "updated_at_ms": int(stat.st_mtime * 1000)}
    except OSError:
        return {"path": str(path), "exists": False, "bytes": 0, "updated_at_ms": 0}


def _safe_read_json(path: Path, default: Any) -> Any:
    try:
        if not path.exists():
            return copy.deepcopy(default)
        data = json.loads(path.read_text(encoding="utf-8-sig"))
        return data if data is not None else copy.deepcopy(default)
    except Exception:
        return copy.deepcopy(default)


def _read_text_file_with_fallback(path: Path, *, max_chars: int = 2_000_000) -> tuple[str, str]:
    raw = path.read_bytes()[: max(0, int(max_chars * 4))]
    for encoding in ("utf-8-sig", "utf-8", "gb18030", "big5", "latin-1"):
        try:
            return raw.decode(encoding), encoding
        except UnicodeDecodeError:
            continue
    return raw.decode("utf-8", errors="replace"), "utf-8-replace"


def _runtime_merge_strategy(value: Any) -> str:
    text = str(value or "stack").strip().lower()
    aliases = {
        "add": "stack",
        "merge": "stack",
        "append": "stack",
        "overlay": "stack",
        "叠加": "stack",
        "stack_average": "stack_average",
        "average": "stack_average",
        "soft_stack": "stack_average",
        "柔和叠加": "stack_average",
        "覆盖": "overwrite",
        "replace": "overwrite",
        "competition": "competitive",
        "compete": "competitive",
        "竞争合并": "competitive",
        "退避": "retreat",
        "keep": "retreat",
        "skip": "retreat",
        "叠加": "stack",
        "柔和叠加": "stack_average",
        "平均叠加": "stack_average",
        "覆盖": "overwrite",
        "竞争": "competitive",
        "竞争合并": "competitive",
        "退避": "retreat",
    }
    text = aliases.get(text, text)
    if text not in {"stack", "stack_average", "overwrite", "competitive", "retreat"}:
        text = "stack"
    return text


def _looks_like_weight_key(key: Any) -> bool:
    text = str(key or "").strip().lower()
    return text in {
        "weight",
        "score",
        "value",
        "energy",
        "drive",
        "strength",
        "confidence",
        "importance",
        "probability",
        "activation",
        "rank",
    } or text.endswith(("_weight", "_score", "_energy", "_strength", "_drive"))


def _looks_like_time_key(key: Any) -> bool:
    text = str(key or "").strip().lower()
    return text in {"created_at", "updated_at", "created_at_ms", "updated_at_ms", "ts", "timestamp", "timestamp_ms"} or text.endswith(("_at", "_at_ms", "_time", "_time_ms"))


def _merge_number_value(old: Any, new: Any, strategy: str) -> Any:
    old_num = _as_float(old, 0.0)
    new_num = _as_float(new, 0.0)
    if strategy == "stack_average":
        return (old_num + new_num) / 2.0
    if strategy == "competitive":
        return old if old_num >= new_num else new
    if strategy == "overwrite":
        return new
    if strategy == "retreat":
        return old
    return old_num + new_num


def _merge_runtime_payload(old: Any, new: Any, *, strategy: str = "stack", key_hint: str = "") -> Any:
    strategy = _runtime_merge_strategy(strategy)
    if old is None:
        return copy.deepcopy(new)
    if new is None:
        return copy.deepcopy(old)
    if strategy == "overwrite":
        return copy.deepcopy(new)
    if strategy == "retreat":
        return copy.deepcopy(old)
    if isinstance(old, (int, float)) and isinstance(new, (int, float)):
        if _looks_like_time_key(key_hint):
            return max(old, new)
        if _looks_like_weight_key(key_hint) or strategy in {"stack", "stack_average"}:
            return _merge_number_value(old, new, strategy)
        return copy.deepcopy(new if strategy == "competitive" and _as_float(new) > _as_float(old) else old)
    if isinstance(old, dict) and isinstance(new, dict):
        merged = copy.deepcopy(old)
        for key, value in new.items():
            if key not in merged:
                merged[key] = copy.deepcopy(value)
            else:
                merged[key] = _merge_runtime_payload(merged.get(key), value, strategy=strategy, key_hint=str(key))
        return merged
    if isinstance(old, list) and isinstance(new, list):
        rows = copy.deepcopy(old)
        keyed: dict[str, int] = {}
        for idx, item in enumerate(rows):
            if isinstance(item, dict):
                identity = str(item.get("id") or item.get("key") or item.get("name") or item.get("title") or "")
                if identity:
                    keyed[identity] = idx
            else:
                keyed[json.dumps(item, ensure_ascii=False, sort_keys=True, default=str)] = idx
        for item in new:
            if isinstance(item, dict):
                identity = str(item.get("id") or item.get("key") or item.get("name") or item.get("title") or "")
                if identity and identity in keyed:
                    idx = keyed[identity]
                    rows[idx] = _merge_runtime_payload(rows[idx], item, strategy=strategy)
                    continue
                if identity:
                    keyed[identity] = len(rows)
                rows.append(copy.deepcopy(item))
            else:
                identity = json.dumps(item, ensure_ascii=False, sort_keys=True, default=str)
                if identity not in keyed:
                    keyed[identity] = len(rows)
                    rows.append(copy.deepcopy(item))
        return rows
    if old == new:
        return copy.deepcopy(old)
    if strategy == "competitive":
        if isinstance(old, (str, bytes, bytearray)) and isinstance(new, (str, bytes, bytearray)):
            return copy.deepcopy(new if len(new) > len(old) else old)
        return copy.deepcopy(new)
    return [copy.deepcopy(old), copy.deepcopy(new)] if old != new else copy.deepcopy(old)


def _sqlite_decode_payload(blob: Any, codec: Any = "") -> tuple[Any, str]:
    raw = bytes(blob or b"")
    codec_text = str(codec or "").strip().lower()
    if not raw:
        return None, codec_text or "json"
    candidates: list[tuple[str, bytes]] = []
    if codec_text in {"zlib+json", "zlib", "compressed"}:
        try:
            candidates.append(("zlib+json", zlib.decompress(raw)))
        except Exception:
            pass
    candidates.append((codec_text or "json", raw))
    if not any(name == "zlib+json" for name, _ in candidates):
        try:
            candidates.append(("zlib+json", zlib.decompress(raw)))
        except Exception:
            pass
    for candidate_codec, data in candidates:
        try:
            return json.loads(data.decode("utf-8")), candidate_codec or "json"
        except Exception:
            continue
    return None, codec_text or "binary"


def _sqlite_encode_payload(payload: Any, codec: str = "json") -> bytes:
    data = json.dumps(payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8")
    if str(codec or "").strip().lower() in {"zlib+json", "zlib", "compressed"}:
        return zlib.compress(data)
    return data


def _safe_copytree_contents(src: Path, dst: Path, *, ignore_patterns: tuple[str, ...] = ()) -> int:
    copied = 0
    if not src.exists():
        return 0
    for item in src.rglob("*"):
        rel = item.relative_to(src)
        rel_text = str(rel).replace("\\", "/")
        if any(fnmatch.fnmatch(rel_text, pattern) for pattern in ignore_patterns):
            continue
        target = dst / rel
        if item.is_dir():
            target.mkdir(parents=True, exist_ok=True)
            continue
        target.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(item, target)
        copied += 1
    return copied


def _safe_extract_zip(zip_file: ZipFile, dst: Path) -> list[str]:
    extracted: list[str] = []
    root = dst.resolve()
    for info in zip_file.infolist():
        name = str(info.filename or "").replace("\\", "/")
        parts = [part for part in name.split("/") if part not in {"", "."}]
        if not parts or any(part == ".." for part in parts):
            raise ValueError(f"unsafe zip path: {name}")
        target = (root / Path(*parts)).resolve()
        try:
            inside = target.is_relative_to(root)
        except AttributeError:  # pragma: no cover - Python < 3.9 fallback
            inside = str(target).startswith(str(root) + str(Path.sep))
        if not inside:
            raise ValueError(f"unsafe zip path: {name}")
        if info.is_dir() or name.endswith("/"):
            target.mkdir(parents=True, exist_ok=True)
            continue
        target.parent.mkdir(parents=True, exist_ok=True)
        with zip_file.open(info, "r") as src, target.open("wb") as out:
            shutil.copyfileobj(src, out)
        extracted.append(name)
    return extracted


def _sanitize_runtime_package_config(config: dict[str, Any]) -> dict[str, Any]:
    safe = copy.deepcopy(config if isinstance(config, dict) else {})
    for secret_key in _CONFIG_SECRET_KEYS + _CONFIG_SECRET_MASK_KEYS:
        safe[secret_key] = ""
    for key, value in list(safe.items()):
        key_text = str(key).lower()
        if any(token in key_text for token in ("url", "endpoint", "base_url", "webhook", "host")):
            if str(value or "").strip():
                safe[key] = ""
    for row in _as_list(safe.get("model_pool")):
        if isinstance(row, dict):
            for secret_key in _CONFIG_SECRET_KEYS + _CONFIG_SECRET_MASK_KEYS:
                row[secret_key] = ""
            for key, value in list(row.items()):
                key_text = str(key).lower()
                if any(token in key_text for token in ("url", "endpoint", "base_url", "webhook", "host")) and str(value or "").strip():
                    row[key] = ""
    return safe


def _zip_write_path(zip_file: ZipFile, file_path: Path, arcname: str) -> None:
    if not file_path.exists() or not file_path.is_file():
        return
    zip_file.write(file_path, arcname.replace("\\", "/"))


def _zip_write_json(zip_file: ZipFile, arcname: str, payload: Any) -> None:
    zip_file.writestr(arcname.replace("\\", "/"), _json_bytes(payload, compact=False))


def _merge_sqlite_store_file(target: Path, incoming: Path, *, strategy: str = "stack") -> dict[str, Any]:
    strategy = _runtime_merge_strategy(strategy)
    if not incoming.exists():
        return {"ok": False, "error": "incoming_missing", "target": str(target), "incoming": str(incoming)}
    target.parent.mkdir(parents=True, exist_ok=True)
    if not target.exists():
        shutil.copy2(incoming, target)
        return {"ok": True, "mode": "copied_new_sqlite", "inserted": 0, "updated": 0, "skipped": 0, "target": str(target)}
    inserted = 0
    updated = 0
    skipped = 0
    errors: list[str] = []
    src = sqlite3.connect(str(incoming))
    dst = sqlite3.connect(str(target))
    try:
        src.row_factory = sqlite3.Row
        dst.row_factory = sqlite3.Row
        src_tables = {str(row[0]) for row in src.execute("SELECT name FROM sqlite_master WHERE type='table'")}
        dst_tables = {str(row[0]) for row in dst.execute("SELECT name FROM sqlite_master WHERE type='table'")}
        for table in sorted(src_tables & dst_tables):
            if table.startswith("sqlite_"):
                continue
            columns = [str(row[1]) for row in dst.execute(f"PRAGMA table_info({table})")]
            src_columns = [str(row[1]) for row in src.execute(f"PRAGMA table_info({table})")]
            common = [col for col in columns if col in src_columns]
            if not common:
                continue
            key_candidates = [col for col in ("id", "structure_db_id", "owner_structure_id", "key", "name") if col in common]
            if not key_candidates:
                skipped += int(src.execute(f"SELECT COUNT(*) FROM {table}").fetchone()[0] or 0)
                continue
            key_col = key_candidates[0]
            placeholders = ",".join("?" for _ in common)
            update_clause = ",".join(f"{col}=?" for col in common)
            for row in src.execute(f"SELECT {','.join(common)} FROM {table}"):
                incoming_row = {col: row[col] for col in common}
                key = incoming_row.get(key_col)
                existing = dst.execute(f"SELECT {','.join(common)} FROM {table} WHERE {key_col}=?", (key,)).fetchone()
                if existing is None:
                    dst.execute(f"INSERT INTO {table} ({','.join(common)}) VALUES ({placeholders})", [incoming_row.get(col) for col in common])
                    inserted += 1
                    continue
                if strategy == "retreat":
                    skipped += 1
                    continue
                if strategy == "overwrite":
                    merged_row = incoming_row
                else:
                    existing_row = {col: existing[col] for col in common}
                    merged_row = copy.deepcopy(existing_row)
                    if "payload" in common:
                        old_payload, old_codec = _sqlite_decode_payload(existing_row.get("payload"), existing_row.get("codec"))
                        new_payload, new_codec = _sqlite_decode_payload(incoming_row.get("payload"), incoming_row.get("codec"))
                        if old_payload is not None and new_payload is not None:
                            codec = old_codec if old_codec != "binary" else new_codec
                            merged_row["payload"] = _sqlite_encode_payload(
                                _merge_runtime_payload(old_payload, new_payload, strategy=strategy),
                                codec=codec,
                            )
                            if "codec" in common:
                                merged_row["codec"] = codec
                        elif strategy == "competitive":
                            if len(bytes(incoming_row.get("payload") or b"")) > len(bytes(existing_row.get("payload") or b"")):
                                merged_row["payload"] = incoming_row.get("payload")
                    for col in common:
                        if col == "payload":
                            continue
                        if col.endswith("_at") or col.endswith("_ms") or col == "updated_at":
                            merged_row[col] = max(_as_int(existing_row.get(col), 0), _as_int(incoming_row.get(col), 0)) or incoming_row.get(col) or existing_row.get(col)
                        elif col not in merged_row or merged_row.get(col) in (None, ""):
                            merged_row[col] = incoming_row.get(col)
                dst.execute(f"UPDATE {table} SET {update_clause} WHERE {key_col}=?", [merged_row.get(col) for col in common] + [key])
                updated += 1
        dst.commit()
    except Exception as exc:
        dst.rollback()
        errors.append(str(exc))
    finally:
        src.close()
        dst.close()
    return {
        "ok": not errors,
        "mode": "sqlite_merge",
        "strategy": strategy,
        "target": str(target),
        "incoming": str(incoming),
        "inserted": inserted,
        "updated": updated,
        "skipped": skipped,
        "errors": errors,
    }


def _persist_inline_attachment_data_url(data_url: str, *, index: int = 0, name: str = "") -> dict[str, Any]:
    text = str(data_url or "").strip()
    if not text.startswith("data:") or ";base64," not in text:
        return {}
    header, payload = text.split(",", 1)
    mime = header[5:].split(";", 1)[0] or "application/octet-stream"
    try:
        raw = base64.b64decode(payload, validate=False)
    except Exception:
        return {"inline_data_redacted": True, "inline_data_error": "base64_decode_failed", "inline_data_chars": len(payload)}
    ext = "bin"
    if mime == "image/png":
        ext = "png"
    elif mime in {"image/jpeg", "image/jpg"}:
        ext = "jpg"
    elif mime == "image/gif":
        ext = "gif"
    elif mime == "image/webp":
        ext = "webp"
    digest = hashlib.sha256(raw).hexdigest()
    safe_name = re.sub(r"[^a-zA-Z0-9._-]+", "_", Path(str(name or "")).stem).strip("._-")[:40]
    filename = f"inline_{digest[:16]}_{safe_name or index}.{ext}"
    path = _incoming_attachments_dir() / filename
    try:
        if not path.exists():
            path.write_bytes(raw)
    except Exception:
        return {"inline_data_redacted": True, "inline_data_error": "write_failed", "inline_data_bytes": len(raw), "content_sha256": digest}
    return {
        "file": str(path),
        "mime_type": mime,
        "size": len(raw),
        "content_sha256": digest,
        "inline_data_saved": True,
        "inline_data_redacted": True,
    }


def _safe_write_json(path: Path, payload: Any) -> None:
    safe_payload = _redact_large_inline_data(payload, max_string_chars=_MAX_SNAPSHOT_BYTES)
    data = _json_bytes(safe_payload, compact=False)
    if len(data) > _MAX_SNAPSHOT_BYTES:
        safe_payload = {
            "truncated": True,
            "reason": "json_payload_too_large",
            "original_bytes": len(data),
            "preview": _redact_large_inline_data(payload, max_string_chars=1200, depth=0),
        }
        data = _json_bytes(safe_payload, compact=False)
    _safe_write_bytes(path, data)


def _safe_write_asset_json(path: Path, payload: Any, *, compact: bool = False, backup: bool = True) -> None:
    data = _json_bytes(payload, compact=compact)
    if len(data) > _MAX_ASSET_JSON_BYTES:
        raise ValueError(f"asset json too large: {len(data)} bytes > {_MAX_ASSET_JSON_BYTES}")
    if backup:
        _backup_existing_file(path, timestamped=False)
        if len(data) > _MAX_SNAPSHOT_BYTES:
            _backup_existing_file(path, timestamped=True)
    _safe_write_bytes(path, data)


def _safe_write_json_compact(path: Path, payload: Any) -> None:
    safe_payload = _redact_large_inline_data(payload)
    data = _json_bytes(safe_payload, compact=True)
    if len(data) > _MAX_STATE_BYTES:
        _backup_existing_file(path, timestamped=False)
        _backup_existing_file(path, timestamped=True)
        if len(data) <= _MAX_ASSET_JSON_BYTES:
            _safe_write_bytes(path, data)
            return
        oversized_path = path.with_name(f"{path.stem}.oversized.{time.strftime('%Y%m%d-%H%M%S', time.localtime())}.json")
        try:
            _safe_write_bytes(oversized_path, data)
            _prune_oversized_state_backups(path)
        except Exception:
            oversized_path = Path()
        safe_payload = {
            "session_id": _as_dict(payload).get("session_id") if isinstance(payload, dict) else "",
            "created_at_ms": _as_dict(payload).get("created_at_ms") if isinstance(payload, dict) else _now_ms(),
            "updated_at_ms": _now_ms(),
            "truncated": True,
            "reason": "state_payload_too_large",
            "original_bytes": len(data),
            "oversized_state_path": str(oversized_path) if oversized_path else "",
            "messages": _as_list(_as_dict(payload).get("messages"))[-20:] if isinstance(payload, dict) else [],
            "thoughts": _as_list(_as_dict(payload).get("thoughts"))[-12:] if isinstance(payload, dict) else [],
            "turns": _as_list(_as_dict(payload).get("turns"))[-8:] if isinstance(payload, dict) else [],
            "snapshots": _as_list(_as_dict(payload).get("snapshots"))[-12:] if isinstance(payload, dict) else [],
            "outbound": _as_dict(_as_dict(payload).get("outbound")) if isinstance(payload, dict) else {},
        }
        safe_payload = _redact_large_inline_data(safe_payload, max_string_chars=1600)
        data = _json_bytes(safe_payload, compact=True)
    _safe_write_bytes(path, data)


def _append_jsonl(path: Path, payload: dict[str, Any]) -> None:
    _rotate_jsonl_if_needed(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    row = _redact_large_inline_data(payload, max_string_chars=2000)
    line = json.dumps(row, ensure_ascii=False, separators=(",", ":"))
    if len(line) > _MAX_JSON_ROW_CHARS:
        row = {
            "ts": _as_dict(payload).get("ts", _now_ms()),
            "event": _short(_as_dict(payload).get("event") or path.stem, 160),
            "level": _short(_as_dict(payload).get("level") or "info", 40),
            "truncated": True,
            "reason": "jsonl_row_too_large",
            "original_chars": len(line),
            "preview": _short(line, 4000),
        }
        line = json.dumps(row, ensure_ascii=False, separators=(",", ":"))
    with path.open("a", encoding="utf-8") as fh:
        fh.write(line + "\n")
    _rotate_jsonl_if_needed(path)


def _read_jsonl_tail(path: Path, *, limit: int = 80) -> list[dict[str, Any]]:
    limit = max(1, min(1000, int(limit or 80)))
    if not path.exists():
        return []
    rows: list[dict[str, Any]] = []
    try:
        lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
    except Exception:
        return []
    for line in lines[-limit:]:
        try:
            value = json.loads(line)
            if isinstance(value, dict):
                rows.append(value)
        except Exception:
            continue
    return rows


def _count_lines(path: Path) -> int:
    try:
        if not path.exists():
            return 0
        return len(path.read_text(encoding="utf-8", errors="replace").splitlines())
    except Exception:
        return 0


def _trim_jsonl(path: Path, *, limit: int = 500) -> None:
    limit = max(20, min(5000, int(limit or 500)))
    try:
        if not path.exists():
            return
        lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
        if len(lines) <= limit:
            return
        path.write_text("\n".join(lines[-limit:]) + "\n", encoding="utf-8")
    except Exception:
        return


def _mask_secret(value: str) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    if len(text) <= 8:
        return "*" * len(text)
    return f"{text[:3]}...{text[-4:]}"


_CONFIG_SECRET_KEYS = ("api_key", "vision_api_key", "multimodal_api_key", "image_generation_api_key", "library_review_api_key")
_CONFIG_SECRET_MASK_KEYS = tuple(f"{key}_masked" for key in _CONFIG_SECRET_KEYS)


def _slug_id(value: Any, *, fallback: str = "profile") -> str:
    text = str(value or "").strip().lower()
    text = re.sub(r"[^a-z0-9._-]+", "_", text)
    text = re.sub(r"_+", "_", text).strip("._-")
    return text[:48] or fallback


def _clean_text(value: Any, *, max_chars: int = 4000) -> str:
    text = str(value or "")
    text = text.replace("\ufffd", " ")
    text = re.sub(r"\?{5,}", " ", text)
    text = re.sub(r"？{5,}", " ", text)
    text = re.sub(r"\s+", " ", text.replace("\u0000", " ")).strip()
    if len(text) > max_chars:
        return text[: max(0, max_chars - 12)].rstrip() + "...[cut]"
    return text


def _clean_multiline_text(value: Any, *, max_chars: int = 4000) -> str:
    text = str(value or "")
    text = text.replace("\ufffd", " ").replace("\u0000", " ")
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    text = re.sub(r"\?{5,}", " ", text)
    text = re.sub(r"？{5,}", " ", text)
    text = "\n".join(re.sub(r"[ \t\f\v]+", " ", line).strip() for line in text.split("\n"))
    text = re.sub(r"\n{4,}", "\n\n\n", text).strip()
    if len(text) > max_chars:
        return text[: max(0, max_chars - 12)].rstrip() + "...[cut]"
    return text



def _short(value: Any, max_chars: int = 90) -> str:
    text = _clean_text(value, max_chars=max_chars + 20)
    if len(text) <= max_chars:
        return text
    return text[: max(0, max_chars - 3)].rstrip() + "..."


