def _strip_debug_fragments(text: str) -> str:
    cleaned = str(text or "")
    cleaned = _INTERNAL_SIGNAL_RE.sub(" ", cleaned)
    cleaned = _TOOL_ERROR_KV_RE.sub(" ", cleaned)
    cleaned = _TOOL_ERROR_RE.sub(" ", cleaned)
    patterns = [
        r"\b(?:st|em|sa|spi)_[0-9A-Za-z_:-]+\b",
        r"(?:时间感受|内容预览|附件摘要|工具结果|工具返回)\s*[:=：]?\s*[^。！？\n]+",
        r"\b(?:total_er|total_ev|total_cp|ev_to_er_ratio|object_cloud|dominant_objects|active_item_count|packet_id|memory_id|structure_id)\b\s*[:=：]?\s*[^,，。；;\n]+",
        r"\b(?:ER|EV|CP|NT|CFS)\b\s*[:：][^。！？\n]*",
        r"(?:整体内在态势|主要感受|高能对象|高能量对象|高能记忆|高认知压对象|对象云|状态包|运行阶段|分析过程|工具调用|行动决策|调试说明|认知感受摘要|情绪通道摘要)\s*[:：][^。！？\n]*",
        r"\b(?:decision|reply_text|reply|tool_calls|tool|why|confidence|action|source|ok)\b\s*[:=：]?\s*[^,，。；;\n]+",
    ]
    for pattern in patterns:
        cleaned = re.sub(pattern, " ", cleaned, flags=re.I)
    cleaned = _strip_diagnostic_narrative_fragments(cleaned)
    return cleaned


