def _looks_like_diagnostic_narrative_echo(value: Any) -> bool:
    text = str(value or "")
    if not text:
        return False
    compact = re.sub(r"\s+", "", text)
    if not compact:
        return False
    if any(phrase in compact for phrase in _DIAGNOSTIC_ECHO_STRONG_PHRASES):
        return True
    weak_hits = sum(1 for phrase in _DIAGNOSTIC_ECHO_WEAK_PHRASES if phrase in compact)
    if weak_hits >= 2:
        return True
    return bool(
        weak_hits >= 1
        and re.search(r"(现在最|最醒目|我又|线索|旁边|整理|开口)", compact)
        and len(compact) >= 14
    )


def _has_diagnostic_narrative_leak(value: Any) -> bool:
    text = _clean_text(value, max_chars=2400)
    if not text:
        return False
    return _looks_like_diagnostic_narrative_echo(text) or any(
        re.search(pattern, text, flags=re.I) for pattern in _DIAGNOSTIC_NARRATIVE_PATTERNS
    )


def _strip_diagnostic_narrative_fragments(value: Any) -> str:
    text = str(value or "")
    if not text:
        return ""
    if _looks_like_diagnostic_narrative_echo(text):
        return ""
    for pattern in _DIAGNOSTIC_NARRATIVE_PATTERNS:
        text = re.sub(pattern, " ", text, flags=re.I)
    if _looks_like_diagnostic_narrative_echo(text):
        return ""
    text = re.sub(r"\s+", " ", text).strip()
    return text


def _plain_compact_text(value: Any, *, max_chars: int = 320) -> str:
    text = _clean_text(value, max_chars=max_chars)
    text = re.sub(r"[\s/，。！？；:：,.;+|()\[\]{}<>\"'`~-]+", "", text)
    return text.strip()


def _naturalize_runtime_text(value: Any, *, max_chars: int = 320) -> str:
    text = _clean_text(value, max_chars=max_chars + 800)
    if not text:
        return ""
    text = text.replace("\r", "\n").replace("||", "，")
    text = re.sub(r"\s*\+\s*", "", text)
    text = _DISPLAY_ONLY_MARKERS_RE.sub(" ", text)
    text = _strip_debug_fragments(text)
    text = re.sub(r"\s*/\s*", "，", text)
    text = re.sub(r"(?<!\d)\.\d+\b", " ", text)
    text = re.sub(r"，{2,}", "，", text)
    text = re.sub(r"\s+", " ", text)
    text = re.sub(r"([，。！？；：,.!?;:])\1+", r"\1", text)
    text = text.strip(" /，。；;:,-")
    return _short(text, max_chars) if len(text) > max_chars else text


def _sanitize_text_for_ap_ingest(value: Any, *, max_chars: int = 2400) -> str:
    text = _naturalize_runtime_text(value, max_chars=max_chars)
    if not text:
        return ""
    text = re.sub(r"\b(?:image|file|audio|video|text)\s*:\s*", "", text, flags=re.I)
    text = re.sub(r"\s+", " ", text).strip()
    return _clean_text(text, max_chars=max_chars)


def _sanitize_object_display_text(value: Any, *, max_chars: int = 220, preserve_action_hint: bool = True) -> str:
    text = _naturalize_runtime_text(value, max_chars=max_chars + 220)
    if not text:
        return ""
    text = re.sub(r"^(?:系统反馈|内部提示|工具结果|执行记录)\s*[:：]\s*", "", text, flags=re.I)
    text = _INTERNAL_SIGNAL_RE.sub(" ", text)
    text = _INTERNAL_SIGNAL_NAME_RE.sub(" ", text)
    text = _TOOL_ERROR_KV_RE.sub(" ", text)
    text = _TOOL_ERROR_RE.sub(" ", text)
    text = re.sub(r"\b(?:ok|success|failure|reason|latency_ms|scheduled_tick_number|due_tick_number)\b\s*[:=：]?\s*[^,，。；;\n]+", " ", text, flags=re.I)
    text = re.sub(r"\b(?:action_kind|action_id|target_item_id|target_ref_object_id|target_ref_object_type)\b\s*[:=：]?\s*[^,，。；;\n]+", " ", text, flags=re.I)
    text = re.sub(r"(?:系统反馈文本|工具返回文本|反馈文本)\s*[:：]\s*", "", text, flags=re.I)
    if not preserve_action_hint:
        text = re.sub(r"^行动节点[:：]?", "", text)
    text = re.sub(r"\s*\/\s*", "，", text)
    text = re.sub(r"，{2,}", "，", text)
    text = re.sub(r"\s+", " ", text).strip(" /，。；;:,-")
    return _short(text, max_chars) if len(text) > max_chars else text


def _is_weather_action_kind(kind: Any) -> bool:
    normalized = str(kind or "").strip().lower().replace("-", "_")
    return normalized in _WEATHER_ACTION_KINDS


def _raw_display_of(row: dict[str, Any]) -> str:
    for key in (
        "semantic_display_text",
        "semantic_grouped_display_text",
        "display",
        "display_text",
        "grouped_display_text",
        "text",
        "content",
        "summary",
        "content_display",
        "content_display_detail",
        "ref_object_id",
        "id",
    ):
        value = row.get(key)
        if value is not None and str(value).strip():
            return str(value)
    return ""


def _raw_display_has_internal_noise(value: Any) -> bool:
    raw = str(value or "")
    return bool(
        _INTERNAL_SIGNAL_NAME_RE.search(raw)
        or _TOOL_ERROR_RE.search(raw)
        or re.search(
            r"(?:teacher_|current_drive|effective_threshold|threshold_scale|drive=|"
            r"weather_stub|llm_think_wake|后台主观能动性唤醒|ap在静默运行中出现了值得整理成想法的状态)",
            raw,
            flags=re.I,
        )
    )


def _raw_display_has_fatal_noise(value: Any) -> bool:
    raw = str(value or "")
    return bool(
        _TOOL_ERROR_RE.search(raw)
        or re.search(
            r"(?:teacher_|current_drive|effective_threshold|threshold_scale|drive=|"
            r"weather_stub|llm_think_wake|后台主观能动性唤醒|ap在静默运行中出现了值得整理成想法的状态)",
            raw,
            flags=re.I,
        )
    )


def _is_noise_object_display(value: Any, *, object_type: str = "", raw_value: Any = None) -> bool:
    raw = str(value if raw_value is None else raw_value or "")
    display = _sanitize_object_display_text(value, max_chars=320)
    if not display:
        return True
    plain = _plain_compact_text(display, max_chars=320)
    if not plain:
        return True
    if _raw_display_has_fatal_noise(raw):
        return True
    if _INTERNAL_SIGNAL_NAME_RE.search(raw) and (len(plain) < 8 or display.count("/") >= 2):
        return True
    if re.fullmatch(r"[A-Za-z0-9_]+", plain) and len(plain) <= 3:
        return True
    if object_type.lower() in {"st", "sa", "unknown"} and len(plain) < 2:
        return True
    if object_type.lower() in {"st", "sa", "unknown"} and len(plain) < 4 and re.fullmatch(r"[\u4e00-\u9fffA-Za-z0-9]+", plain):
        return True
    digit_count = sum(1 for ch in plain if ch.isdigit())
    if digit_count >= max(3, int(len(plain) * 0.4)):
        return True
    if len(plain) >= 18 and re.fullmatch(r"[A-Za-z0-9_]+", plain):
        return True
    if display.count("/") >= 5:
        return True
    return False


