def _nt_channel_meta(channel: Any) -> dict[str, Any]:
    code = str(channel or "").strip().upper()
    meta = dict(_NT_CHANNEL_ZH.get(code, {}))
    meta.setdefault("label_zh", code)
    meta.setdefault("analogy_zh", "")
    meta.setdefault("meaning", "该情绪/递质样通道当下更占前景。")
    return meta


def _normalize_cfs_name(value: Any) -> str:
    text = str(value or "").strip()
    if text.lower().startswith("cfs_"):
        text = text[4:]
    return text


def _cfs_display_name(value: Any) -> str:
    name = _normalize_cfs_name(value)
    if not name:
        return ""
    return _CFS_NAME_ZH.get(name.lower(), name)


def _cfs_meaning(value: Any) -> str:
    name = _normalize_cfs_name(value)
    if not name:
        return "高值表示这一类认知感受更明显；低值表示它仍在背景中。"
    return _CFS_MEANING_ZH.get(name.lower(), "高值表示这一类认知感受更明显；低值表示它仍在背景中。")


def _sanitize_cfs_target(value: Any, *, max_chars: int = 90) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    if raw.startswith("{") and "target_ref_object_id" in raw:
        return "内部目标对象"
    text = _sanitize_object_display_text(raw, max_chars=max_chars)
    if not text or _raw_display_has_internal_noise(raw):
        return "内部目标对象"
    return text


def _sanitize_cognitive_feelings(rows: list[Any], *, limit: int = 10) -> list[dict[str, Any]]:
    cleaned: list[dict[str, Any]] = []
    seen: set[str] = set()
    for item in rows:
        if not isinstance(item, dict):
            continue
        name = _normalize_cfs_name(item.get("name") or item.get("kind") or item.get("signal_name"))
        if not name:
            continue
        key = name.lower()
        if key in seen:
            continue
        seen.add(key)
        cleaned.append(
            {
                "name": name,
                "label_zh": _cfs_display_name(name),
                "level": round(_as_float(item.get("level", item.get("strength", item.get("energy", 0.0))), 0.0), 6),
                "meaning": item.get("meaning") or item.get("note") or _cfs_meaning(name),
                "target": _sanitize_cfs_target(item.get("target") or item.get("target_ref_object_id") or "", max_chars=90),
                "reason": _sanitize_object_display_text(item.get("reason") or item.get("source") or "", max_chars=120),
            }
        )
        if len(cleaned) >= max(1, int(limit or 10)):
            break
    return cleaned


def _sanitize_llm_visible_text(value: Any, *, max_chars: int = 220) -> str:
    text = _sanitize_object_display_text(value, max_chars=max_chars + 60)
    if not text:
        return ""
    text = _strip_diagnostic_narrative_fragments(text)
    if not text:
        return ""
    text = re.sub(r"\b(?:st|em|sa|spi)_[0-9A-Za-z_:-]+\b", "内部对象", text)
    text = re.sub(r"\b(?:total_er|total_ev|total_cp|ev_to_er_ratio|object_cloud|dominant_objects)\b", "内部指标", text)
    text = re.sub(r"\b(?:cfs_[0-9A-Za-z_:-]*|punish_signal|reward_signal)\b", "内部调制线索", text, flags=re.I)
    text = re.sub(r"\bNT\b\s*[:：]?\s*[A-Za-z,\s/]+", "情绪通道线索", text, flags=re.I)
    text = re.sub(r"\s+", " ", text).strip()
    return _short(text, max_chars)


def _as_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except Exception:
        return float(default)


def _as_int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except Exception:
        return int(default)


def _report_tick_counter(report: dict[str, Any] | None) -> int:
    report = report if isinstance(report, dict) else {}
    value = _as_int(report.get("tick_counter", report.get("tick_number", 0)), 0)
    if value:
        return value
    match = re.search(r"(\d+)$", str(report.get("tick_id") or ""))
    return int(match.group(1)) if match else 0


def _as_list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


def _as_dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


