def _energy_of(row: dict[str, Any]) -> dict[str, float]:
    er = _as_float(row.get("er", row.get("total_er", row.get("memory_er", 0.0))))
    ev = _as_float(row.get("ev", row.get("total_ev", row.get("memory_ev", 0.0))))
    cp = _as_float(row.get("cp_abs", row.get("cp", row.get("total_cp", 0.0))))
    total = _as_float(row.get("total_energy", row.get("energy", er + ev)))
    if total <= 0:
        total = er + ev
    return {
        "er": round(max(0.0, er), 8),
        "ev": round(max(0.0, ev), 8),
        "cp": round(max(0.0, cp), 8),
        "total": round(max(0.0, total), 8),
    }


def _display_of(row: dict[str, Any]) -> str:
    raw = _raw_display_of(row)
    if raw:
        text = _sanitize_object_display_text(raw, max_chars=320)
        text = re.sub(r"^(?:内心想法|回复用户|工具结果)\s*[:：]\s*", "", text)
        if text:
            return text
    return "-"


def _summarize_tool_output(output: Any, *, max_chars: int = 600) -> str:
    if isinstance(output, dict):
        if output.get("mode") in {"read_diary", "write_diary", "schedule_task"} or output.get("entry") or output.get("entries") or output.get("tasks"):
            parts: list[str] = []
            for key in ("summary", "message", "mode"):
                value = output.get(key)
                if value not in (None, "", [], {}):
                    parts.append(f"{key}={value}")
            entries = _as_list(output.get("entries"))
            if entries:
                compact_entries = []
                for entry in entries[:6]:
                    item = _as_dict(entry)
                    compact_entries.append(
                        {
                            "id": item.get("id") or "",
                            "title": item.get("title") or "",
                            "importance": item.get("importance"),
                            "updated_at": item.get("updated_at") or item.get("updated_at_ms") or "",
                            "preview": _short(item.get("preview") or item.get("content") or "", 180),
                        }
                    )
                parts.append("entries=" + json.dumps(compact_entries, ensure_ascii=False))
            entry = _as_dict(output.get("entry"))
            if entry:
                parts.append(
                    "entry="
                    + json.dumps(
                        {
                            "id": entry.get("id") or "",
                            "title": entry.get("title") or "",
                            "importance": entry.get("importance"),
                            "updated_at": entry.get("updated_at") or entry.get("updated_at_ms") or "",
                            "preview": _short(entry.get("preview") or entry.get("content") or "", 220),
                        },
                        ensure_ascii=False,
                    )
                )
            removed = _as_list(output.get("removed_entries"))
            if removed:
                parts.append(f"removed={len(removed)}")
            tasks = _as_list(output.get("tasks"))
            if tasks:
                compact_tasks = []
                for task in tasks[:8]:
                    item = _as_dict(task)
                    compact_tasks.append(
                        {
                            "id": item.get("id") or "",
                            "summary": item.get("summary") or "",
                            "status": item.get("status") or "",
                            "next_fire_at": item.get("next_fire_at") or item.get("next_fire_at_ms") or "",
                            "prompt": _short(item.get("prompt") or "", 160),
                        }
                    )
                parts.append("tasks=" + json.dumps(compact_tasks, ensure_ascii=False))
            cancelled = _as_list(output.get("cancelled_tasks"))
            if cancelled:
                parts.append(f"cancelled={len(cancelled)}")
            warnings = _as_list(output.get("warnings"))
            if warnings:
                parts.append("warnings=" + "；".join(str(item) for item in warnings[:3]))
            if parts:
                return _naturalize_runtime_text("；".join(parts), max_chars=max_chars)
        if output.get("mode") in {"browse_library", "read_book", "import_book"} or output.get("book") or output.get("books") or output.get("review"):
            parts: list[str] = []
            for key in ("summary", "view", "path"):
                value = output.get(key)
                if value not in (None, "", [], {}):
                    parts.append(f"{key}={_short(value, 260)}")
            book = _as_dict(output.get("book"))
            if book:
                parts.append(
                    "book="
                    + json.dumps(
                        {
                            "id": book.get("id") or "",
                            "title": book.get("title") or "",
                            "progress": book.get("progress") or "",
                            "cursor": book.get("cursor") or 0,
                            "char_count": book.get("char_count") or 0,
                        },
                        ensure_ascii=False,
                    )
                )
            books = _as_list(output.get("books"))
            if books:
                compact_books = []
                for item in books[:8]:
                    row = _as_dict(item)
                    compact_books.append({"id": row.get("id") or "", "title": row.get("title") or "", "progress": row.get("progress") or ""})
                parts.append("books=" + json.dumps(compact_books, ensure_ascii=False))
            chunk = _as_dict(output.get("chunk"))
            if chunk:
                parts.append("chunk=" + json.dumps({"start": chunk.get("start"), "end": chunk.get("end"), "text": _short(chunk.get("text"), 220)}, ensure_ascii=False))
            review = _as_dict(output.get("review"))
            if review:
                understanding = _clean_multiline_text(review.get("understanding") or review.get("summary") or "", max_chars=900)
                parts.append(
                    "段落理解="
                    + json.dumps(
                        {
                            "id": review.get("id") or "",
                            "title": review.get("title") or "",
                            "range": review.get("range") or {},
                            "summary": understanding,
                        },
                        ensure_ascii=False,
                    )
                )
            reviews = _as_list(output.get("reviews"))
            if reviews:
                compact_reviews = []
                for item in reviews[:6]:
                    row = _as_dict(item)
                    compact_reviews.append({"id": row.get("id") or "", "title": row.get("title") or "", "range": row.get("range") or {}})
                parts.append("reviews=" + json.dumps(compact_reviews, ensure_ascii=False))
            if parts:
                return _naturalize_runtime_text("；".join(parts), max_chars=max_chars)
        if output.get("mode") == "image_generation" or output.get("attachment") or output.get("send_recommendation"):
            parts: list[str] = []
            for key in ("summary", "path", "file", "send_recommendation", "next"):
                value = output.get(key)
                if value not in (None, "", [], {}):
                    parts.append(f"{key}={value}")
            attachment = _as_dict(output.get("attachment"))
            if attachment:
                parts.append(
                    "attachment="
                    + json.dumps(
                        {
                            "kind": attachment.get("kind"),
                            "name": attachment.get("name"),
                            "file": attachment.get("file"),
                            "path": attachment.get("path"),
                            "url": attachment.get("url"),
                        },
                        ensure_ascii=False,
                    )
                )
            review = _as_dict(output.get("review"))
            if review:
                parts.append(
                    "review="
                    + json.dumps(
                        {
                            "ok": bool(review.get("ok")),
                            "send_recommendation": review.get("send_recommendation") or "",
                            "summary": _sanitize_object_display_text(review.get("summary"), max_chars=360),
                        },
                        ensure_ascii=False,
                    )
                )
            if parts:
                return _naturalize_runtime_text("；".join(parts), max_chars=max_chars)
        for key in ("summary", "message", "text", "content", "note", "result"):
            value = output.get(key)
            if value is not None and str(value).strip():
                return _naturalize_runtime_text(value, max_chars=max_chars)
        if output.get("ok") is False:
            return ""
        parts: list[str] = []
        for key, value in output.items():
            if isinstance(value, (str, int, float, bool)) and str(value).strip():
                parts.append(f"{key}={value}")
            elif isinstance(value, list) and value:
                sample = [str(item).strip() for item in value[:3] if str(item).strip()]
                if sample:
                    parts.append(f"{key}=" + "，".join(sample))
            if len(parts) >= 6:
                break
        return _naturalize_runtime_text("；".join(parts), max_chars=max_chars)
    if isinstance(output, list):
        parts = [str(item).strip() for item in output[:6] if str(item).strip()]
        return _naturalize_runtime_text("；".join(parts), max_chars=max_chars)
    return _naturalize_runtime_text(output, max_chars=max_chars)


def _safe_tool_feedback_text(result: dict[str, Any], *, max_chars: int = 420) -> str:
    result = result if isinstance(result, dict) else {}
    tool = _canonical_tool_name(result.get("tool") or "tool")
    ok = bool(result.get("ok"))
    output = _as_dict(result.get("output"))
    existing = _sanitize_text_for_ap_ingest(result.get("summary", ""), max_chars=max_chars)
    if existing:
        return existing
    if ok:
        text = _summarize_tool_output(result.get("output"), max_chars=max_chars)
        return _sanitize_text_for_ap_ingest(text, max_chars=max_chars)
    if tool in {"browse_library", "read_book", "import_book"}:
        text = _summarize_tool_output(result.get("output"), max_chars=max_chars)
        if text:
            return _sanitize_text_for_ap_ingest(text, max_chars=max_chars)
        return "图书馆工具这次没有成功返回可用结果；我需要检查书籍 id、导入路径或阅读参数后再继续。"
    if tool == "weather":
        location = (
            output.get("normalized_location")
            or output.get("location")
            or _as_dict(result.get("args")).get("location")
            or _as_dict(result.get("args")).get("city")
            or ""
        )
        location_text = _sanitize_object_display_text(location, max_chars=80)
        if location_text:
            return f"天气工具这次没有成功返回 {location_text} 的结果，我需要稍后重试或换一种查询方式。"
        return "天气工具这次没有成功返回结果，我需要稍后重试或换一种查询方式。"
    label = {
        "time": "时间工具",
            "memory_note": "记忆便签工具",
            "write_diary": "写日记工具",
            "read_diary": "查日记工具",
            "web_search": "搜索工具",
            "image_understanding": "视觉理解工具",
            "mcp_ping": "MCP 状态工具",
            "skill_run": "Skill 状态工具",
            "reply_action": "回复动作",
        }.get(tool, f"{tool} 工具")
    return f"{label}这次没有成功返回可用结果，我会把它当成一次失败的行动反馈，而不是事实内容。"


def _public_object_id(value: Any, *, object_type: str = "") -> str:
    oid = str(value or "").strip()
    if not oid:
        return ""
    if _PUBLIC_ID_LEAK_RE.search(oid):
        otype = str(object_type or "object").strip().lower()
        digest = hashlib.sha1(oid.encode("utf-8", errors="ignore")).hexdigest()[:10]
        return f"pa_{otype or 'object'}_{digest}"
    return oid


def _public_tool_result(result: dict[str, Any], *, max_summary_chars: int = 260) -> dict[str, Any]:
    result = result if isinstance(result, dict) else {}
    tool = _canonical_tool_name(result.get("tool") or "tool")
    ok = bool(result.get("ok"))
    output = _as_dict(result.get("output"))
    public_output: dict[str, Any] = {}
    for key in (
        "summary",
        "message",
        "text",
        "content",
        "note",
        "result",
        "understanding",
        "normalized_location",
        "location",
        "provider",
        "path",
        "file",
        "send_recommendation",
        "next",
    ):
        value = output.get(key)
        if value not in (None, "", [], {}):
            public_output[key] = _sanitize_object_display_text(value, max_chars=240)
    if isinstance(output.get("attachment"), dict):
        att = _normalize_attachment(_as_dict(output.get("attachment")), index=0)
        public_output["attachment"] = {
            "kind": att.get("kind"),
            "name": att.get("name"),
            "file": att.get("file"),
            "path": att.get("path"),
            "url": att.get("url"),
        }
    if isinstance(output.get("review"), dict):
        review = _as_dict(output.get("review"))
        public_output["review"] = {
            "id": review.get("id") or "",
            "title": review.get("title") or "",
            "book_id": review.get("book_id") or "",
            "range": review.get("range") or {},
            "summary": _sanitize_object_display_text(review.get("summary") or review.get("understanding"), max_chars=900),
        }
    if not ok:
        public_output["feedback"] = _safe_tool_feedback_text(result, max_chars=max_summary_chars)
    return {
        "ok": ok,
        "tool": tool,
        "latency_ms": _as_int(result.get("latency_ms"), 0),
        "summary": _safe_tool_feedback_text(result, max_chars=max_summary_chars),
        "output": public_output,
    }


def _object_id_of(row: dict[str, Any]) -> str:
    for key in ("ref_object_id", "object_id", "item_id", "memory_id", "structure_id", "id"):
        value = row.get(key)
        if value is not None and str(value).strip():
            return str(value)
    return ""


def _object_type_of(row: dict[str, Any]) -> str:
    for key in ("ref_object_type", "object_type", "type", "kind"):
        value = row.get(key)
        if value is not None and str(value).strip():
            return str(value)
    oid = _object_id_of(row)
    if oid.startswith("em_"):
        return "em"
    if oid.startswith("st_"):
        return "st"
    if oid.startswith("sa_"):
        return "sa"
    return "unknown"


def _compact_object(row: dict[str, Any], *, rank: int = 0) -> dict[str, Any]:
    energy = _energy_of(row)
    oid = _object_id_of(row)
    otype = _object_type_of(row)
    raw_display = _raw_display_of(row) or _display_of(row)
    display = _sanitize_object_display_text(raw_display, max_chars=220)
    full_display = _sanitize_object_display_text(raw_display, max_chars=420)
    return {
        "rank": rank,
        "id": oid,
        "type": otype,
        "display": display,
        "full_display": full_display or display,
        "er": energy["er"],
        "ev": energy["ev"],
        "cp": energy["cp"],
        "total_energy": energy["total"],
        "ev_ratio": round(energy["ev"] / max(1e-9, energy["er"] + energy["ev"]), 6),
        "source": _short(row.get("source_module") or _as_dict(row.get("source")).get("module") or row.get("reason") or "", 80),
        "raw_ref": {
            "item_id": row.get("item_id"),
            "ref_object_id": row.get("ref_object_id"),
            "ref_object_type": row.get("ref_object_type"),
        },
    }


def _public_object_row(row: dict[str, Any]) -> dict[str, Any]:
    row = dict(row if isinstance(row, dict) else {})
    otype = str(row.get("type") or row.get("ref_object_type") or row.get("object_type") or "object")
    display = _sanitize_object_display_text(row.get("display") or row.get("full_display") or "", max_chars=260)
    full_display = _sanitize_object_display_text(row.get("full_display") or row.get("display") or "", max_chars=640)
    if _looks_like_diagnostic_narrative_echo(display) or _looks_like_diagnostic_narrative_echo(full_display):
        display = ""
        full_display = ""
    row["display"] = display
    if full_display:
        row["full_display"] = full_display
    elif "full_display" in row:
        row["full_display"] = ""
    row["id"] = _public_object_id(row.get("id"), object_type=otype)
    if isinstance(row.get("raw_ref"), dict):
        raw_ref = dict(row.get("raw_ref") or {})
        raw_ref["item_id"] = _public_object_id(raw_ref.get("item_id"), object_type=otype)
        raw_ref["ref_object_id"] = _public_object_id(raw_ref.get("ref_object_id"), object_type=otype)
        row["raw_ref"] = raw_ref
    if isinstance(row.get("source_ids"), list):
        row["source_ids"] = [_public_object_id(item, object_type=otype) for item in row.get("source_ids", [])]
    return row


def _public_object_rows(rows: list[Any], *, limit: int | None = None) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        public = _public_object_row(row)
        if not str(public.get("display") or "").strip() and not str(public.get("full_display") or "").strip():
            continue
        out.append(public)
        if limit is not None and len(out) >= max(0, int(limit)):
            break
    return out


def _fast_public_object_rows(rows: list[Any], *, limit: int | None = None) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    max_rows = None if limit is None else max(0, int(limit))
    for row in rows:
        if not isinstance(row, dict):
            continue
        display = str(row.get("display") or row.get("full_display") or "").strip()
        full_display = str(row.get("full_display") or display).strip()
        if not display:
            display = _sanitize_object_display_text(full_display, max_chars=220)
        if not full_display:
            full_display = display
        display = _sanitize_object_display_text(display, max_chars=260)
        full_display = _sanitize_object_display_text(full_display, max_chars=640)
        if _looks_like_diagnostic_narrative_echo(display) or _looks_like_diagnostic_narrative_echo(full_display):
            continue
        out.append(
            {
                "rank": _as_int(row.get("rank"), len(out) + 1),
                "id": str(row.get("id") or row.get("ref_object_id") or row.get("item_id") or ""),
                "type": str(row.get("type") or row.get("ref_object_type") or row.get("object_type") or ""),
                "display": _short(display, 260),
                "full_display": _short(full_display, 640),
                "er": _as_float(row.get("er"), 0.0),
                "ev": _as_float(row.get("ev"), 0.0),
                "cp": _as_float(row.get("cp", row.get("cp_abs")), 0.0),
                "total_energy": _as_float(row.get("total_energy"), _as_float(row.get("er"), 0.0) + _as_float(row.get("ev"), 0.0)),
                "ev_ratio": _as_float(row.get("ev_ratio"), 0.0),
                "source": str(row.get("source") or ""),
            }
        )
        if max_rows is not None and len(out) >= max_rows:
            break
    return out


def _compact_state_item(row: dict[str, Any], *, rank: int = 0) -> dict[str, Any]:
    obj = _compact_object(row, rank=rank)
    return {
        "rank": obj.get("rank", rank),
        "id": obj.get("id", ""),
        "type": obj.get("type", ""),
        "display": obj.get("display", ""),
        "er": obj.get("er", 0.0),
        "ev": obj.get("ev", 0.0),
        "cp": obj.get("cp", 0.0),
        "total_energy": obj.get("total_energy", 0.0),
    }


def _sanitize_object_rows(rows: list[Any], *, limit: int = 8, types: set[str] | None = None) -> list[dict[str, Any]]:
    return _top_objects([row for row in rows if isinstance(row, dict)], limit=limit, types=types)


def _llm_object_hint(row: dict[str, Any], *, max_display: int = 120) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    raw_display = _raw_display_of(row) or row.get("display", "")
    if _looks_like_diagnostic_narrative_echo(raw_display):
        hint = ""
    else:
        hint = _sanitize_llm_visible_text(row.get("display") or raw_display, max_chars=max_display)
    if _is_noise_object_display(hint, object_type=str(row.get("type") or ""), raw_value=raw_display or hint):
        hint = ""
    return {
        "kind": row.get("type", ""),
        "hint": hint,
        "energy": row.get("total_energy", 0.0),
        "reality_evidence": row.get("er", 0.0),
        "association_energy": row.get("ev", 0.0),
        "cognitive_pressure": row.get("cp", 0.0),
        "association_ratio": row.get("ev_ratio", 0.0),
    }


def _llm_object_hints(rows: list[Any], *, limit: int = 8, types: set[str] | None = None, max_display: int = 120) -> list[dict[str, Any]]:
    hints: list[dict[str, Any]] = []
    for row in _top_objects(rows, limit=max(limit * 3, limit), types=types):
        if not isinstance(row, dict):
            continue
        hint = _llm_object_hint(row, max_display=max_display)
        if not str(hint.get("hint") or "").strip():
            continue
        hints.append(hint)
        if len(hints) >= max(0, int(limit or 0)):
            break
    return hints


def _top_objects(rows: list[Any], *, limit: int = 12, types: set[str] | None = None) -> list[dict[str, Any]]:
    compacted: list[dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        raw_display = _raw_display_of(row)
        obj = _compact_object(row)
        if _is_noise_object_display(obj.get("display"), object_type=str(obj.get("type") or ""), raw_value=raw_display or obj.get("display")):
            continue
        if types and str(obj.get("type", "")).lower() not in types:
            continue
        compacted.append(obj)
    compacted.sort(key=lambda item: float(item.get("total_energy", 0.0) or 0.0), reverse=True)
    return [{**item, "rank": idx + 1} for idx, item in enumerate(compacted[: max(1, int(limit or 12))])]


def _extract_json_object(text: str) -> dict[str, Any] | None:
    raw = str(text or "").strip()
    if not raw:
        return None
    candidates = [raw]
    fenced = re.findall(r"```(?:json)?\s*(\{.*?\})\s*```", raw, flags=re.S | re.I)
    candidates.extend(fenced)
    start = raw.find("{")
    end = raw.rfind("}")
    if start >= 0 and end > start:
        candidates.append(raw[start : end + 1])
    for candidate in candidates:
        try:
            value = json.loads(candidate)
            if isinstance(value, dict):
                return value
        except Exception:
            continue
    return None


def _first_nested_value(value: Any, keys: tuple[str, ...]) -> Any:
    if not isinstance(value, dict):
        return None
    for key in keys:
        if value.get(key) not in (None, "", [], {}):
            return value.get(key)
    for nested_key in ("data", "result", "response"):
        nested = value.get(nested_key)
        if isinstance(nested, dict):
            found = _first_nested_value(nested, keys)
            if found not in (None, "", [], {}):
                return found
    return None


def _parse_loose_llm_payload(text: str) -> dict[str, Any]:
    raw = str(text or "").strip()
    if not raw:
        return {}
    raw = re.sub(r"```(?:json)?", "", raw, flags=re.I).replace("```", "").strip()
    tagged = re.search(r"<(?:thought|想法|内心想法)>\s*(.*?)\s*</(?:thought|想法|内心想法)>", raw, flags=re.S | re.I)
    if tagged:
        return {"thought": _clean_text(tagged.group(1), max_chars=1800), "_raw_text": raw}

    label_map = {
        "thought": "thought",
        "thought_text": "thought",
        "inner_thought": "thought",
        "想法": "thought",
        "内心想法": "thought",
        "叙事化想法": "thought",
        "reply": "reply_text",
        "reply_text": "reply_text",
        "回复": "reply_text",
        "回复文本": "reply_text",
        "decision": "decision",
        "action": "decision",
        "行动": "decision",
        "决策": "decision",
        "tool": "tool_calls",
        "tools": "tool_calls",
        "tool_calls": "tool_calls",
        "工具": "tool_calls",
        "why": "why",
        "reason": "why",
        "原因": "why",
        "confidence": "confidence",
        "置信度": "confidence",
    }
    sections: dict[str, list[str]] = {}
    current = ""
    for line in raw.splitlines():
        match = re.match(r"^\s*([A-Za-z_]+|[\u4e00-\u9fff]{2,8})\s*[:：]\s*(.*)$", line)
        if match:
            key = label_map.get(match.group(1).strip().lower()) or label_map.get(match.group(1).strip())
            if key:
                current = key
                sections.setdefault(current, []).append(match.group(2).strip())
                continue
        if current:
            sections.setdefault(current, []).append(line.strip())
    result: dict[str, Any] = {"_raw_text": raw}
    for key, lines in sections.items():
        value = _clean_text("\n".join(line for line in lines if line), max_chars=2600)
        if key == "tool_calls":
            parsed = _extract_json_object(value)
            result[key] = _as_list(parsed.get("tool_calls")) if isinstance(parsed, dict) else []
        elif key == "confidence":
            result[key] = _as_float(value, 0.55)
        else:
            result[key] = value
    if not result.get("thought"):
        cleaned_lines = []
        blocked = re.compile(r"^\s*(decision|reply|reply_text|tool|tools|tool_calls|why|confidence|行动|决策|回复|工具|原因|置信度)\s*[:：]", re.I)
        for line in raw.splitlines():
            if blocked.match(line):
                continue
            cleaned_lines.append(line)
        result["thought"] = _clean_text("\n".join(cleaned_lines), max_chars=1800)
    return result


def _clean_thought_text(value: Any, *, max_chars: int = 1800) -> str:
    text = str(value or "")
    text = re.sub(r"```(?:json)?|```", "", text, flags=re.I)
    text = re.sub(r"</?(?:thought|想法|内心想法)>", "", text, flags=re.I)
    kept: list[str] = []
    blocked = re.compile(
        r"^\s*(?:decision|reply|reply_text|tool|tools|tool_calls|ap_feedback|confidence|why|action|"
        r"决策|回复|回复文本|工具|置信度|原因|行动|反馈)\s*[:：]",
        re.I,
    )
    for line in text.splitlines():
        if blocked.match(line):
            continue
        kept.append(line)
    text = "\n".join(kept).strip()
    if text.startswith("{") and text.endswith("}"):
        parsed = _extract_json_object(text)
        if parsed:
            text = str(parsed.get("thought") or parsed.get("thought_text") or parsed.get("inner_thought") or parsed.get("想法") or "")
    text = _strip_debug_fragments(text)
    text = re.sub(r"^\s*(?:thought|thought_text|inner_thought|想法|内心想法|叙事化想法)\s*[:：]\s*", "", text, flags=re.I)
    text = text.replace("`", "").replace("||", " ").replace("{", "").replace("}", "").replace("[", "").replace("]", "")
    text = text.replace("<", "").replace(">", "")
    text = text.replace("“", "").replace("”", "").replace("\"", "")
    text = text.replace("（", "，").replace("）", "").replace("(", "，").replace(")", "")
    text = re.sub(r"[�]+", "", text)
    text = re.sub(r"[?？]{4,}", "…", text)
    blocked_line = re.compile(
        r"(?:整体内在态势|主要感受|高能对象|高能量对象|高能记忆|高认知压对象|对象云|状态包|AP\s*内在状态|"
        r"当前状态包|运行阶段|分析过程|工具调用|行动决策|调试说明|认知感受摘要|情绪通道摘要)\s*[:：]",
        re.I,
    )
    inline_leaks = [
        r"(?:整体内在态势|主要感受|高能对象|高能量对象|高能记忆|高认知压对象|对象云|状态包|AP\s*内在状态|当前状态包)\s*[:：][^。！？\n]*",
        r"\b(?:ER|EV|CP|NT|CFS)\b\s*[:：][^。！？\n]*",
        r"\b(?:st|em|sa|spi)_[0-9A-Za-z_:-]+\b",
    ]
    kept: list[str] = []
    for raw_line in re.split(r"[\r\n]+", text):
        line = raw_line.strip().strip("-•*")
        if not line:
            continue
        if blocked_line.search(line):
            continue
        if re.search(r"\b(?:st|em|sa|spi)_[0-9A-Za-z_:-]+\b", line):
            continue
        for pattern in inline_leaks:
            line = re.sub(pattern, "", line, flags=re.I)
        line = _strip_diagnostic_narrative_fragments(line)
        if _has_diagnostic_narrative_leak(line):
            continue
        line = _strip_debug_fragments(line)
        line = re.sub(r"[|\\/]{2,}", " ", line)
        line = re.sub(r"\s*/\s*", "，", line)
        line = re.sub(r"\s*\+\s*", "", line)
        line = re.sub(r"\b(?:teacher_reward_signal|teacher_punish_signal|reward_signal|punish_signal|cfs_[A-Za-z0-9_:-]+)\b\s*[:=：]?\s*[-+]?\d*(?:\.\d+)?", " ", line, flags=re.I)
        line = re.sub(r"\s+", " ", line).strip(" ，,；;：:-")
        if not line:
            continue
        if re.fullmatch(r"[\W_]+", line):
            continue
        kept.append(line)
    text = " ".join(kept) if kept else text
    text = re.sub(r"\s*([，。！？])\s*", r"\1", text)
    text = re.sub(r"([，。！？]){2,}", r"\1", text)
    text = re.sub(r"\s+", " ", text).strip()
    return _clean_text(text, max_chars=max_chars)


def _clean_reply_text(value: Any, *, max_chars: int = 3000) -> str:
    text = _clean_text(value, max_chars=max_chars + 600)
    if not text:
        return ""
    text = _strip_debug_fragments(text)
    text = re.sub(r"\b(?:st|em|sa|spi)_[0-9A-Za-z_:-]+\b", "", text)
    text = re.sub(r"\b(?:teacher_reward_signal|teacher_punish_signal|reward_signal|punish_signal|cfs_[A-Za-z0-9_:-]+)\b\s*[:=：]?\s*[-+]?\d*(?:\.\d+)?", " ", text, flags=re.I)
    text = text.replace("||", " ").replace("{", "").replace("}", "").replace("[", "").replace("]", "")
    text = re.sub(r"\s*\+\s*", "", text)
    text = re.sub(r"[|\\/]{2,}", " ", text)
    text = re.sub(r"\s+", " ", text).strip()
    text = _strip_diagnostic_narrative_fragments(text)
    if _has_diagnostic_narrative_leak(text):
        return ""
    return _clean_text(text, max_chars=max_chars)


def _thought_has_operator_leak(value: Any) -> bool:
    text = _clean_text(value, max_chars=2200)
    if not text:
        return True
    patterns = [
        r"\b(?:ER|EV|CP|NT|CFS)\b\s*[:：]?",
        r"(?:整体内在态势|主要感受|高能对象|高能量对象|高能记忆|高认知压对象|对象云|状态包|AP\s*内在状态|当前状态包)",
        r"\b(?:st|em|sa|spi)_[0-9A-Za-z_:-]+\b",
        r"(?:工具调用|行动决策|调试说明|分析过程)\s*[:：]?",
    ]
    if any(re.search(pattern, text, flags=re.I) for pattern in patterns):
        return True
    if _has_diagnostic_narrative_leak(text):
        return True
    return bool(re.search(r"[?？]{4,}|[�]{1,}", text))


def _listify_strings(value: Any, fallback: list[str]) -> list[str]:
    if isinstance(value, list):
        items = [str(item).strip() for item in value if str(item).strip()]
        return items or list(fallback)
    if isinstance(value, str):
        items = [part.strip() for part in re.split(r"[,，\n]", value) if part.strip()]
        return items or list(fallback)
    return list(fallback)


def _optional_string_list(value: Any) -> list[str]:
    if isinstance(value, list):
        return [str(item).strip() for item in value if str(item).strip()]
    if isinstance(value, str):
        return [part.strip() for part in re.split(r"[,，、\n]", value) if part.strip()]
    if value in (None, "", [], {}):
        return []
    return [str(value).strip()] if str(value).strip() else []


def _contains_any_alias(text: Any, aliases: Any) -> bool:
    lowered = str(text or "").lower()
    if not lowered:
        return False
    for alias in _as_list(aliases):
        key = str(alias or "").strip().lower().lstrip("@")
        if not key:
            continue
        if key in lowered or f"@{key}" in lowered:
            return True
    return False


def _expanded_alias_tokens(values: Any, *, include_small_prefix: bool = True) -> list[str]:
    tokens: list[str] = []
    for value in _as_list(values):
        plain = str(value or "").strip()
        if not plain:
            continue
        tokens.append(plain)
        for part in re.split(r"[/／,，、\s]+", plain):
            part = part.strip()
            if not part:
                continue
            tokens.append(part)
            if include_small_prefix and len(part) >= 2:
                tokens.append(f"小{part.lstrip('小')}")
    return list(dict.fromkeys(tokens))


def _normalize_trigger_modes(value: Any, fallback: Any = None, *, allow_empty: bool = False) -> list[str]:
    fallback_items = _listify_strings(fallback, _DEFAULT_TRIGGER_MODES)
    if isinstance(value, list):
        raw_items = [str(item).strip() for item in value if str(item).strip()]
        if not raw_items and allow_empty:
            return []
        items = raw_items or fallback_items
    elif isinstance(value, str):
        raw_items = [part.strip() for part in re.split(r"[,，\n]", value) if part.strip()]
        if not raw_items and allow_empty:
            return []
        items = raw_items or fallback_items
    elif value is None and allow_empty:
        return []
    else:
        items = _listify_strings(value, fallback_items)
    out: list[str] = []
    for item in items:
        mode = str(item or "").strip().lower()
        if mode in _TRIGGER_MODE_CHOICES and mode not in out:
            out.append(mode)
    if not out:
        for item in fallback_items:
            mode = str(item or "").strip().lower()
            if mode in _TRIGGER_MODE_CHOICES and mode not in out:
                out.append(mode)
    return out or ([] if allow_empty else list(_DEFAULT_TRIGGER_MODES))


def _trigger_mode_labels(modes: Any, fallback: Any = None, *, allow_empty: bool = False) -> list[str]:
    return [
        _TRIGGER_MODE_LABELS.get(mode, mode)
        for mode in _normalize_trigger_modes(modes, fallback, allow_empty=allow_empty)
    ]


def _normalize_attachment(raw: Any, *, index: int = 0, max_text_chars: int = 1200) -> dict[str, Any]:
    if not isinstance(raw, dict):
        return {"id": f"att_{index}", "kind": "unknown", "name": _short(raw, 80), "text_preview": _short(raw, 120)}
    mime = str(raw.get("mime_type") or raw.get("content_type") or "").strip()
    raw_kind_or_type = str(raw.get("kind") or raw.get("type") or "").strip().lower()
    name = _short(raw.get("name") or raw.get("filename") or raw.get("file_name") or raw.get("file") or f"attachment_{index}", 120)
    text = _clean_text(raw.get("text") or raw.get("content") or raw.get("ocr") or raw.get("summary") or "", max_chars=max_text_chars)
    data_url = str(raw.get("data_url") or raw.get("url") or raw.get("file_url") or raw.get("src") or "")
    inline_saved = _persist_inline_attachment_data_url(data_url, index=index, name=name) if data_url.startswith("data:") else {}
    if inline_saved.get("mime_type") and not mime:
        mime = str(inline_saved.get("mime_type") or "")
    kind = str(raw.get("kind") or "").strip().lower()
    known_kinds = {"image", "file", "audio", "video", "text", "sticker", "record"}
    if not kind and raw_kind_or_type in known_kinds:
        kind = "audio" if raw_kind_or_type == "record" else raw_kind_or_type
    if not kind:
        if mime.startswith("image/") or data_url.startswith("data:image/"):
            kind = "image"
        elif mime.startswith("audio/"):
            kind = "audio"
        elif mime.startswith("video/"):
            kind = "video"
        elif text:
            kind = "text"
        else:
            kind = "file"
    size = _as_int(raw.get("size") or raw.get("bytes"), 0)
    file_value = raw.get("file") or raw.get("path") or raw.get("local_path") or raw.get("file_id") or raw.get("fileId")
    source_fields: dict[str, str] = {}
    for key in (
        "file",
        "path",
        "local_path",
        "url",
        "file_url",
        "src",
        "file_id",
        "fileId",
        "file_unique",
        "fileUnique",
        "md5",
        "summary",
        "emoji_id",
        "emojiId",
        "face_id",
        "faceId",
        "sticker_id",
        "stickerId",
        "sub_type",
        "subType",
        "image_type",
        "imageType",
    ):
        value = raw.get(key)
        if value not in (None, "", [], {}):
            source_fields[key] = _short(value, 260)
    sticker_like = bool(raw.get("sticker_like") or raw.get("is_sticker") or kind == "sticker")
    if not sticker_like:
        summary_value = str(raw.get("summary") or raw.get("text") or raw.get("name") or raw.get("file") or "")
        sticker_like = bool(re.search(r"动画表情|表情|贴纸|mface|marketface|bface|sticker", summary_value, flags=re.I))
    out = {
        "id": str(raw.get("id") or f"att_{index}"),
        "kind": kind,
        "name": name,
        "mime_type": mime,
        "size": size,
        "text_preview": text,
        "url_preview": _short(data_url, 180) if data_url and not data_url.startswith("data:") else "",
        "has_inline_data": bool(data_url.startswith("data:")),
    }
    if sticker_like:
        out["sticker_like"] = True
    if source_fields:
        out["source_fields"] = source_fields
    if inline_saved:
        out.update(inline_saved)
        if str(inline_saved.get("file") or ""):
            out["file"] = str(inline_saved.get("file") or "")
    elif data_url:
        if data_url.startswith("data:"):
            redacted = _redact_large_inline_data(data_url)
            out["data_url"] = redacted
            out["inline_data_redacted"] = True
        else:
            out["url"] = data_url
    if file_value not in (None, "", [], {}) and not str(inline_saved.get("file") or ""):
        out["file"] = str(file_value)
    if raw.get("thumbnail") not in (None, "", [], {}):
        out["thumbnail"] = str(raw.get("thumbnail"))
    return out


def _attachment_source_fingerprint(attachment: dict[str, Any] | None) -> str:
    attachment = attachment if isinstance(attachment, dict) else {}
    source_fields = _as_dict(attachment.get("source_fields"))
    candidates = [
        source_fields.get("md5"),
        source_fields.get("file_unique"),
        source_fields.get("fileUnique"),
        source_fields.get("emoji_id"),
        source_fields.get("emojiId"),
        source_fields.get("face_id"),
        source_fields.get("faceId"),
        source_fields.get("sticker_id"),
        source_fields.get("stickerId"),
        attachment.get("md5"),
        attachment.get("file_unique"),
        attachment.get("emoji_id"),
        attachment.get("face_id"),
        attachment.get("sticker_id"),
        attachment.get("file"),
        attachment.get("url"),
        attachment.get("data_url"),
        attachment.get("name"),
    ]
    joined = "|".join(str(item).strip() for item in candidates if str(item or "").strip())
    if not joined:
        return ""
    return hashlib.sha1(joined.encode("utf-8", errors="ignore")).hexdigest()


def _looks_like_sticker_attachment(attachment: dict[str, Any] | None) -> bool:
    attachment = attachment if isinstance(attachment, dict) else {}
    if bool(attachment.get("sticker_like")):
        return True
    source_fields = _as_dict(attachment.get("source_fields"))
    for key in ("emoji_id", "emojiId", "face_id", "faceId", "sticker_id", "stickerId"):
        if str(source_fields.get(key) or attachment.get(key) or "").strip():
            return True
    text = " ".join(
        str(value or "")
        for value in (
            attachment.get("text_preview"),
            attachment.get("name"),
            attachment.get("file"),
            attachment.get("url"),
            source_fields.get("summary"),
            source_fields.get("sub_type"),
            source_fields.get("image_type"),
        )
    )
    return bool(re.search(r"动画表情|表情包|贴纸|mface|marketface|bface|emoji|sticker", text, flags=re.I))


def _attachment_summary(attachments: list[dict[str, Any]]) -> str:
    lines: list[str] = []
    for idx, item in enumerate(attachments, start=1):
        kind_label = item.get("kind") or "file"
        if item.get("sticker_like"):
            kind_label = f"{kind_label}/表情包候选"
        source_fields = _as_dict(item.get("source_fields"))
        label = f"{idx}. {kind_label}:{item.get('name') or '-'}"
        meta = []
        if item.get("id"):
            meta.append(f"id={_short(item.get('id'), 80)}")
        if item.get("file"):
            meta.append(f"file={_short(item.get('file'), 140)}")
        if item.get("path"):
            meta.append(f"path={_short(item.get('path'), 140)}")
        source_url = str(item.get("url") or item.get("url_preview") or "").strip()
        if source_url:
            meta.append(f"url={_short(source_url, 160)}")
        for key in ("md5", "file_unique", "fileUnique", "emoji_id", "emojiId", "face_id", "faceId", "sticker_id", "stickerId", "sub_type", "image_type"):
            value = source_fields.get(key)
            if value not in (None, "", [], {}):
                meta.append(f"{key}={_short(value, 90)}")
        if item.get("mime_type"):
            meta.append(str(item.get("mime_type")))
        if _as_int(item.get("size"), 0) > 0:
            meta.append(f"{_as_int(item.get('size'))} bytes")
        if item.get("text_preview"):
            preview = re.sub(r"[?？]{5,}", "…", _sanitize_text_for_ap_ingest(item.get("text_preview"), max_chars=220))
            meta.append(f"内容预览={preview}")
        if item.get("has_inline_data"):
            meta.append("含内联数据")
        if item.get("url") or item.get("file") or item.get("path"):
            meta.append("可尝试预览/读取")
        lines.append(label + (" (" + "，".join(meta) + ")" if meta else ""))
    return "\n".join(lines)


def _attachment_tool_hints(attachments: list[dict[str, Any]], *, context: str = "") -> str:
    rows: list[dict[str, Any]] = []
    for idx, raw in enumerate(attachments[:6], start=1):
        if not isinstance(raw, dict):
            continue
        item = _normalize_attachment(raw, index=idx - 1)
        kind = str(item.get("kind") or "").lower()
        if kind not in {"image", "sticker"} and not bool(item.get("sticker_like")):
            continue
        url_value = str(item.get("url") or "").strip()
        data_url_value = str(item.get("data_url") or "").strip()
        source_fields = _as_dict(item.get("source_fields"))
        args = {
            "attachment_id": item.get("id") or item.get("name") or item.get("file") or f"attachment_{idx}",
            "file": item.get("file") or item.get("path") or "",
            "url": url_value if url_value else "",
            "question": "请结合当前对话判断这张图片/表情包的具体内容、文字、情绪含义和应该如何回应。",
            "context": context or "当前最新用户消息携带图片/表情包，必须读取当前附件，不要根据旧 AP 记忆猜图。",
        }
        rows.append(
            {
                "index": idx,
                "attachment_id": args["attachment_id"],
                "name": item.get("name") or "",
                "file": item.get("file") or "",
                "url": _short(item.get("url") or item.get("url_preview") or "", 220),
                "has_inline_data": bool(data_url_value),
                "sticker_like": bool(item.get("sticker_like")),
                "source_fields": {key: source_fields.get(key) for key in ("md5", "file_unique", "fileUnique", "sub_type", "image_type") if source_fields.get(key)},
                "recommended_tool_call": {"name": "image_understanding", "args": args},
            }
        )
    if not rows:
        return ""
    return json.dumps(rows, ensure_ascii=False, indent=2)


