    def __post_init__(self) -> None:
        legacy_mode = str(self.trigger_mode or "private_all").strip().lower()
        if legacy_mode not in _TRIGGER_MODE_CHOICES:
            legacy_mode = "private_all"
        raw_modes = _listify_strings(self.trigger_modes, [])
        if raw_modes == list(_DEFAULT_TRIGGER_MODES) and legacy_mode != "private_all":
            self.trigger_modes = _legacy_trigger_modes(legacy_mode)
        else:
            self.trigger_modes = _normalize_trigger_modes(raw_modes, _legacy_trigger_modes(legacy_mode), allow_empty=True)
        self.trigger_mode = self.trigger_modes[0] if self.trigger_modes else legacy_mode

