    def run(self, name: Any, args: dict[str, Any] | None = None, *, source: str = "manual_tool", context: dict[str, Any] | None = None) -> dict[str, Any]:
        tool_name = _canonical_tool_name(name)
        args = args if isinstance(args, dict) else {}
        context = context if isinstance(context, dict) else {}
        started = _now_ms()
        allowed = self._allowed(tool_name)
        if not allowed:
            result = {
                "ok": False,
                "tool": tool_name,
                "error": "tool_not_allowed",
                "allowlist": list(self.runtime.config.tool_allowlist),
                "latency_ms": 0,
            }
            self.runtime.record_event({"event": "tool_blocked", "tool": tool_name, "source": source, "args_preview": self._preview_args(args)})
            return result

        try:
            if tool_name == "time":
                output = self._tool_time(args)
            elif tool_name == "weather":
                output = self._tool_weather(args)
            elif tool_name == "memory_note":
                output = self._tool_memory_note(args)
            elif tool_name == "write_diary":
                output = self.runtime.write_diary(args, source=source)
            elif tool_name == "read_diary":
                output = self.runtime.read_diary(args)
            elif tool_name == "schedule_task":
                output = self.runtime.schedule_task(args, source=source)
            elif tool_name == "browse_library":
                output = self.runtime.browse_library(args)
            elif tool_name == "read_book":
                output = self.runtime.read_book(
                    args,
                    source=source,
                    interrupt_checker=context.get("should_stop") if callable(context.get("should_stop")) else None,
                    progress_emit=context.get("emit") if callable(context.get("emit")) else None,
                )
            elif tool_name == "import_book":
                output = self.runtime.import_book(args, source=source)
            elif tool_name == "timeline_recall":
                output = self._tool_timeline_recall(args)
            elif tool_name == "ap_tick_report":
                output = self._tool_ap_tick_report(args)
            elif tool_name == "ap_recall":
                output = self._tool_ap_recall(args)
            elif tool_name == "ap_attention_focus":
                output = self.runtime.run_ap_attention_focus(args, source=source)
            elif tool_name == "ap_attention_diverge":
                output = self.runtime.run_ap_attention_diverge(args, source=source)
            elif tool_name == "napcat_recall_message":
                output = self.runtime.recall_adapter_message(args, source=source)
            elif tool_name == "background_agency_control":
                output = self.runtime.background_agency_control(args, source=source)
            elif tool_name == "web_search":
                output = self._tool_web_search(args)
            elif tool_name == "image_understanding":
                output = self._tool_image_understanding(args)
            elif tool_name == "image_generation":
                output = self._tool_image_generation(args)
            elif tool_name == "mcp_ping":
                output = self._tool_mcp_ping(args)
            elif tool_name == "skill_run":
                output = self._tool_skill_run(args)
            else:
                output = {"ok": False, "error": "unknown_tool", "known_tools": [item["name"] for item in self.list_tools()]}
        except Exception as exc:
            output = {"ok": False, "error": str(exc)}

        result = {
            "ok": bool(output.get("ok", True)) if isinstance(output, dict) else True,
            "tool": tool_name,
            "args": args,
            "output": output,
            "source": source,
            "created_at_ms": _now_ms(),
            "latency_ms": max(0, _now_ms() - started),
        }
        result["summary"] = _safe_tool_feedback_text(result, max_chars=260)
        self.runtime._mark_tool_progress(tool_name, ok=bool(result.get("ok")), source=source)
        self.runtime.record_event(
            {
                "event": "tool_executed",
                "tool": tool_name,
                "ok": result["ok"],
                "source": source,
                "latency_ms": result["latency_ms"],
                "args_preview": self._preview_args(args),
            }
        )
        return result

    def _allowed(self, name: str) -> bool:
        allowlist = {_canonical_tool_name(item) for item in self.runtime.config.tool_allowlist}
        if name in {"mcp_ping"} and self.runtime.config.mcp_enabled:
            return True
        if name in {"skill_run"} and self.runtime.config.skill_enabled:
            return True
        return name in allowlist

    def _preview_args(self, args: dict[str, Any]) -> dict[str, Any]:
        return {str(key): _short(value, 120) for key, value in list(args.items())[:8]}

    def _tool_time(self, args: dict[str, Any]) -> dict[str, Any]:
        now = time.time()
        return {
            "ok": True,
            "timestamp_ms": int(now * 1000),
            "local_time": time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(now)),
            "utc_time": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(now)),
            "format": str(args.get("format") or "local"),
        }

    def _tool_weather(self, args: dict[str, Any]) -> dict[str, Any]:
        location_raw = _clean_text(args.get("location") or args.get("city") or args.get("name") or "北京", max_chars=120)
        location = self._extract_weather_location(location_raw)
        latitude = _as_float(args.get("latitude") or args.get("lat"), 999.0)
        longitude = _as_float(args.get("longitude") or args.get("lon") or args.get("lng"), 999.0)
        place: dict[str, Any] = {"name": location}
        geocode_url = "https://geocoding-api.open-meteo.com/v1/search"
        matched_query = location
        retry_count = max(1, int(self.runtime.config.retry_count or 0))
        last_geo_error: dict[str, Any] | None = None
        if abs(latitude) > 90 or abs(longitude) > 180:
            variants = self._weather_location_variants(location)
            first: dict[str, Any] = {}
            known = self._known_weather_place(location)
            if known:
                first = known
                matched_query = str(known.get("matched_query") or location)
            for variant in variants:
                if first:
                    break
                query = urllib.parse.urlencode({"name": variant, "count": 5, "language": "zh", "format": "json"})
                geocode_url = f"https://geocoding-api.open-meteo.com/v1/search?{query}"
                geocode = self._http_json(geocode_url, timeout=10, retries=retry_count, provider="Open-Meteo geocoding")
                transport_error = _as_dict(geocode.get("_transport_error"))
                if transport_error:
                    last_geo_error = transport_error
                    continue
                results = _as_list(_as_dict(geocode).get("results"))
                first = self._pick_weather_geocode_result(location, results)
                if first:
                    matched_query = variant
                    break
            if not first:
                for variant in variants:
                    known = self._known_weather_place(variant)
                    if known:
                        first = known
                        matched_query = str(known.get("matched_query") or variant)
                        break
            latitude = _as_float(first.get("latitude"), 999.0)
            longitude = _as_float(first.get("longitude"), 999.0)
            place = first or place
        if abs(latitude) > 90 or abs(longitude) > 180:
            return {
                "ok": False,
                "error": "geocode_failed" if last_geo_error else "location_not_found",
                "location": location_raw,
                "normalized_location": location,
                "provider": "Open-Meteo",
                "normalized_queries": self._weather_location_variants(location),
                "matched_query": matched_query,
                "provider_error": last_geo_error or {},
            }
        params = {
            "latitude": round(latitude, 6),
            "longitude": round(longitude, 6),
            "current": "temperature_2m,relative_humidity_2m,apparent_temperature,precipitation,weather_code,wind_speed_10m",
            "daily": "weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum",
            "timezone": "auto",
        }
        forecast_url = "https://api.open-meteo.com/v1/forecast?" + urllib.parse.urlencode(params)
        forecast = self._http_json(forecast_url, timeout=12, retries=retry_count, provider="Open-Meteo forecast")
        forecast_error = _as_dict(forecast.get("_transport_error"))
        if forecast_error:
            return {
                "ok": False,
                "error": "forecast_unavailable",
                "location": location_raw,
                "normalized_location": location,
                "matched_query": matched_query,
                "provider": "Open-Meteo",
                "provider_error": forecast_error,
                "normalized_queries": self._weather_location_variants(location),
                "coordinates": {"latitude": round(latitude, 6), "longitude": round(longitude, 6)},
                "source_urls": {
                    "forecast": forecast_url,
                    "geocoding": geocode_url,
                },
            }
        current = _as_dict(forecast.get("current"))
        daily = _as_dict(forecast.get("daily"))
        code = _as_int(current.get("weather_code"), -1)
        place_name = _clean_text(
            " ".join(
                part
                for part in (
                    place.get("name"),
                    place.get("admin1"),
                    place.get("country"),
                )
                if part
            )
            or location,
            max_chars=120,
        )
        temp = _as_float(current.get("temperature_2m"), 0.0)
        apparent = _as_float(current.get("apparent_temperature"), temp)
        humidity = _as_int(current.get("relative_humidity_2m"), 0)
        wind = _as_float(current.get("wind_speed_10m"), 0.0)
        precipitation = _as_float(current.get("precipitation"), 0.0)
        weather = self._weather_code_label(code)
        forecast_rows: list[dict[str, Any]] = []
        for idx, day in enumerate(_as_list(daily.get("time"))[:3]):
            forecast_rows.append(
                {
                    "date": day,
                    "weather_code": (_as_list(daily.get("weather_code")) + [None] * 3)[idx],
                    "weather": self._weather_code_label(_as_int((_as_list(daily.get("weather_code")) + [-1] * 3)[idx], -1)),
                    "temperature_min": (_as_list(daily.get("temperature_2m_min")) + [None] * 3)[idx],
                    "temperature_max": (_as_list(daily.get("temperature_2m_max")) + [None] * 3)[idx],
                    "precipitation_sum": (_as_list(daily.get("precipitation_sum")) + [None] * 3)[idx],
                }
            )
        return {
            "ok": True,
            "mode": "open_meteo",
            "provider": "Open-Meteo",
            "provider_note": "Open-Meteo 免费非商业天气 API，无需 API Key。",
            "location": place_name,
            "matched_query": matched_query if abs(latitude) <= 90 and abs(longitude) <= 180 else location,
            "requested_location": location_raw,
            "normalized_location": location,
            "normalized_queries": self._weather_location_variants(location),
            "coordinates": {"latitude": round(latitude, 6), "longitude": round(longitude, 6)},
            "current": current,
            "daily": forecast_rows,
            "summary": (
                f"{place_name} 当前{weather}，气温 {temp:.1f}°C，体感 {apparent:.1f}°C，"
                f"湿度 {humidity}%，风速 {wind:.1f} km/h，降水 {precipitation:.1f} mm。"
            ),
            "source_urls": {
                "forecast": forecast_url,
                "geocoding": geocode_url,
            },
        }

    def _extract_weather_location(self, location: str) -> str:
        text = _clean_text(location, max_chars=120)
        if not text:
            return "北京"
        cleaned = re.sub(r"[?？!！]+", " ", text)
        cleaned = re.sub(r"[，,、/|]+", " ", cleaned)
        cleaned = re.sub(r"\s+", " ", cleaned).strip()
        lowered = cleaned.lower()
        for prefix in _WEATHER_QUERY_PREFIXES:
            if lowered.startswith(prefix.lower()):
                cleaned = cleaned[len(prefix) :].strip()
                lowered = cleaned.lower()
                break
        cleaned = re.sub(r"^(?:今天|现在|目前|此刻|今晚|今早|今天的|现在的)\s*", "", cleaned)
        lowered = cleaned.lower()
        for suffix in sorted(_WEATHER_QUERY_SUFFIXES, key=len, reverse=True):
            if lowered.endswith(suffix.lower()):
                cleaned = cleaned[: max(0, len(cleaned) - len(suffix))].strip()
                lowered = cleaned.lower()
                break
        cleaned = re.sub(
            r"(?:帮我查|帮我看看|查一下|查查|看看|告诉我|想知道|想问|请问|问下|查询|查)\s*",
            " ",
            cleaned,
            flags=re.I,
        )
        cleaned = re.sub(r"(?:那边|那里|当地|这个地方|这个城市|这座城市)$", "", cleaned, flags=re.I)
        cleaned = re.sub(r"\s+", " ", cleaned).strip(" ，,。！？")
        if not cleaned:
            return text

        city_hits: list[tuple[int, str, str]] = []
        province_hits: list[tuple[int, str, str]] = []
        lowered = cleaned.lower()
        for raw_key, alias in _WEATHER_CITY_ALIASES.items():
            key = str(raw_key or "").strip()
            if not key:
                continue
            pos = lowered.find(key.lower())
            if pos >= 0:
                city_hits.append((pos, key, alias))
        for raw_key, alias in _WEATHER_PROVINCE_ALIASES.items():
            key = str(raw_key or "").strip()
            if not key:
                continue
            pos = lowered.find(key.lower())
            if pos >= 0:
                province_hits.append((pos, key, alias))
        city_hits.sort(key=lambda item: (item[0], -len(item[1])))
        province_hits.sort(key=lambda item: (item[0], -len(item[1])))
        city = city_hits[0][2] if city_hits else ""
        province = province_hits[0][2] if province_hits else ""
        if city and province:
            return f"{city}, {province}"
        if city:
            return city
        if province:
            return province
        return cleaned

    def _http_json(self, url: str, *, timeout: int = 10, retries: int = 0, retry_delay_ms: int = 350, provider: str = "") -> dict[str, Any]:
        req = urllib.request.Request(url, headers={"User-Agent": "PsyArch-Agent/0.1"})
        attempts = max(1, int(retries or 0) + 1)
        last_error: dict[str, Any] = {}
        for attempt in range(attempts):
            try:
                with urllib.request.urlopen(req, timeout=timeout) as resp:
                    raw = resp.read(1_000_000).decode("utf-8", errors="replace")
                data = json.loads(raw)
                return data if isinstance(data, dict) else {}
            except urllib.error.HTTPError as exc:
                body = ""
                try:
                    body = exc.read(1200).decode("utf-8", errors="replace")
                except Exception:
                    body = ""
                last_error = {
                    "type": "http_error",
                    "status": int(exc.code or 0),
                    "reason": _clean_text(getattr(exc, "reason", "") or str(exc), max_chars=200),
                    "body_preview": _short(body, 220),
                    "provider": provider,
                    "url": url,
                }
            except urllib.error.URLError as exc:
                last_error = {
                    "type": "url_error",
                    "reason": _clean_text(getattr(exc, "reason", "") or str(exc), max_chars=220),
                    "provider": provider,
                    "url": url,
                }
            except TimeoutError as exc:
                last_error = {
                    "type": "timeout",
                    "reason": _clean_text(str(exc), max_chars=220) or "timeout",
                    "provider": provider,
                    "url": url,
                }
            except json.JSONDecodeError as exc:
                last_error = {
                    "type": "json_decode_error",
                    "reason": _clean_text(str(exc), max_chars=220),
                    "provider": provider,
                    "url": url,
                }
            except Exception as exc:
                last_error = {
                    "type": "request_error",
                    "reason": _clean_text(str(exc), max_chars=220),
                    "provider": provider,
                    "url": url,
                }
            if attempt < attempts - 1:
                time.sleep(max(0.05, min(2.0, retry_delay_ms / 1000.0 * (attempt + 1))))
        return {"_transport_error": last_error}

    def _weather_location_variants(self, location: str) -> list[str]:
        text = _clean_text(location, max_chars=120)
        if not text:
            return ["Beijing", "北京"]
        canonical = re.sub(r"[，,、/|]+", " ", text)
        canonical = re.sub(r"\s+", " ", canonical).strip()
        parts = [part.strip() for part in re.split(r"[ ]+", canonical) if part.strip()]
        city = ""
        province = ""
        for part in parts:
            lowered = part.lower()
            if not city and lowered in _WEATHER_CITY_ALIASES:
                city = _WEATHER_CITY_ALIASES[lowered]
                continue
            if not city and part in _WEATHER_CITY_ALIASES:
                city = _WEATHER_CITY_ALIASES[part]
                continue
            if not province and lowered in _WEATHER_PROVINCE_ALIASES:
                province = _WEATHER_PROVINCE_ALIASES[lowered]
                continue
            if not province and part in _WEATHER_PROVINCE_ALIASES:
                province = _WEATHER_PROVINCE_ALIASES[part]
                continue
        lowered_text = text.lower()
        if not city:
            for raw_key, alias in _WEATHER_CITY_ALIASES.items():
                key = str(raw_key or "").strip()
                if key and key.lower() in lowered_text:
                    city = alias
                    break
        if not province:
            for raw_key, alias in _WEATHER_PROVINCE_ALIASES.items():
                key = str(raw_key or "").strip()
                if key and key.lower() in lowered_text:
                    province = alias
                    break
        if not city and parts:
            city = _WEATHER_CITY_ALIASES.get(parts[0].lower(), parts[0])
        variants: list[str] = []
        for item in (
            text,
            canonical,
            canonical.replace(" ", ", "),
            f"{city}, {province}" if city and province else "",
            f"{province}, {city}" if city and province else "",
            f"{city} {province}" if city and province else "",
            f"{province} {city}" if city and province else "",
            city,
            province,
            text.replace("市", "").replace("省", ""),
        ):
            value = _clean_text(item, max_chars=120)
            if value and value not in variants:
                variants.append(value)
        return variants[:10] or [text]

    def _known_weather_place(self, location: str) -> dict[str, Any]:
        variants = [location, *self._weather_location_variants(location)]
        for variant in variants:
            value = _clean_text(variant, max_chars=120)
            if not value:
                continue
            keys = {
                value,
                value.lower(),
                re.sub(r"\s+", " ", value).strip().lower(),
                re.sub(r"[，,、/|]+", " ", value).strip().lower(),
            }
            for key in keys:
                row = _WEATHER_KNOWN_PLACES.get(key)
                if row:
                    known = copy.deepcopy(row)
                    known["matched_query"] = value
                    return known
        return {}

    def _pick_weather_geocode_result(self, location: str, results: list[Any]) -> dict[str, Any]:
        normalized = _clean_text(location, max_chars=120).lower()
        city_hint = ""
        province_hint = ""
        for token in self._weather_location_variants(location):
            token_clean = _clean_text(token, max_chars=120)
            lowered = token_clean.lower()
            if lowered in _WEATHER_CITY_ALIASES:
                city_hint = _WEATHER_CITY_ALIASES[lowered].lower()
            if lowered in _WEATHER_PROVINCE_ALIASES:
                province_hint = _WEATHER_PROVINCE_ALIASES[lowered].lower()

        best_score = -1.0
        best: dict[str, Any] = {}
        for item in results:
            row = _as_dict(item)
            if not row:
                continue
            name = _clean_text(row.get("name"), max_chars=120).lower()
            admin1 = _clean_text(row.get("admin1"), max_chars=120).lower()
            country = _clean_text(row.get("country"), max_chars=120).lower()
            score = 0.0
            if normalized and normalized in f"{name} {admin1} {country}":
                score += 1.2
            if city_hint and city_hint in name:
                score += 1.5
            if province_hint and province_hint in admin1:
                score += 1.0
            if str(row.get("feature_code") or "").upper() in {"PPLA", "PPLA2", "PPL", "PPLC"}:
                score += 0.1
            if score > best_score:
                best_score = score
                best = row
        if best:
            return best
        return _as_dict(results[0]) if results else {}

