    def polish_persona(self, payload: dict[str, Any] | None = None) -> dict[str, Any]:
        payload = payload if isinstance(payload, dict) else {}
        persona_name = _clean_text(payload.get("persona_name") or self.config.persona_name or "未命名人设", max_chars=120)
        persona_text = _clean_text(payload.get("persona_text") or self.config.persona_text, max_chars=5000)
        diary_seed = _clean_text(payload.get("diary_seed") or self.config.diary_seed, max_chars=2400)
        system_note = _clean_text(payload.get("system_note") or self.config.system_note, max_chars=1800)
        fallback = self._fallback_persona_polish(
            persona_name=persona_name,
            persona_text=persona_text,
            diary_seed=diary_seed,
            system_note=system_note,
        )
        if not (self.config.llm_enabled and self.config.api_key and self.config.model):
            self.record_event({"event": "persona_polish", "mode": "local_fallback", "persona_name": persona_name})
            return {"ok": True, "mode": "local_fallback", **fallback}
        messages = [
            {
                "role": "system",
                "content": (
                    "你是 PA 人设提示词整理器。只输出 JSON object。"
                    "根据用户已有内容，润色扩展成更完整的人设，但不要改变核心身份。"
                    "输出字段：persona_name、persona_text、diary_seed、system_note、sections。"
                    "persona_text 必须包含身份设定、性格设定、外貌设定、表达习惯、情绪特点、关系边界、行动风格。"
                ),
            },
            {
                "role": "user",
                "content": json.dumps(
                    {
                        "persona_name": persona_name,
                        "persona_text": persona_text,
                        "diary_seed": diary_seed,
                        "system_note": system_note,
                    },
                    ensure_ascii=False,
                ),
            },
        ]
        raw, status = self.gateway.generate(messages)
        if not status.get("ok"):
            self.record_event({"event": "persona_polish", "mode": "local_fallback_after_llm_error", "reason": status.get("reason")})
            return {"ok": True, "mode": "local_fallback_after_llm_error", "llm_status": status, **fallback}
        result = {
            "persona_name": _clean_text(raw.get("persona_name") or fallback["persona_name"], max_chars=120),
            "persona_text": _clean_text(raw.get("persona_text") or raw.get("prompt") or fallback["persona_text"], max_chars=8000),
            "diary_seed": _clean_text(raw.get("diary_seed") or fallback["diary_seed"], max_chars=3000),
            "system_note": _clean_text(raw.get("system_note") or fallback["system_note"], max_chars=2400),
            "sections": _as_dict(raw.get("sections")),
        }
        self.record_event({"event": "persona_polish", "mode": "llm", "persona_name": result["persona_name"], "ok": True})
        return {"ok": True, "mode": "llm", "llm_status": status, **result}

    def _fallback_persona_polish(self, *, persona_name: str, persona_text: str, diary_seed: str, system_note: str) -> dict[str, Any]:
        base = persona_text or "请在这里填写完整角色身份、性格、说话习惯、关系边界和禁忌。"
        sections = {
            "身份设定": "完全沿用用户草稿中的身份设定；本地润色不会新增固定姓名、职业或角色模板。",
            "性格设定": "从用户草稿中提炼性格关键词；如果草稿为空，请先补写而不是套用默认角色。",
            "外貌设定": "只保留用户草稿明确给出的外貌信息；没有写就留空或标注待补充。",
            "表达习惯": "从用户草稿中提炼句式、长度、语气、禁用词和平台口吻。",
            "情绪特点": "把 AP 实时状态当成表达底色，但不覆盖用户草稿指定的人设风格。",
            "关系边界": "只根据用户草稿和系统补充确定关系、隐私和禁忌，不混入旧人设。",
            "行动风格": "根据用户草稿决定回复、潜水、执行命令、拒绝请求等行为倾向。",
        }
        persona_lines = [base, ""]
        for title, value in sections.items():
            persona_lines.append(f"{title}：{value}")
        return {
            "persona_name": persona_name,
            "persona_text": _clean_text("\n".join(persona_lines), max_chars=8000),
            "diary_seed": diary_seed
            or "",
            "system_note": _clean_text(
                (system_note + "\n\n" if system_note else "")
                + "生成 thought 时必须保持纯净内心文本；工具调用、行动决策、回复文本放在结构化字段中，由 PA 后端执行和审计。角色身份、姓名、口吻和禁忌只来自用户保存的人设文本。",
                max_chars=2400,
            ),
            "sections": sections,
        }

    def list_tools(self) -> dict[str, Any]:
        return {
            "tools": self.tools.list_tools(),
            "allowlist": list(self.config.tool_allowlist),
            "mcp_enabled": bool(self.config.mcp_enabled),
            "skill_enabled": bool(self.config.skill_enabled),
        }

    def tool_matrix(self) -> dict[str, Any]:
        tools = self.tools.list_tools()
        mutating_tools = {"memory_note", "write_diary", "schedule_task", "read_book", "import_book", "ap_recall", "ap_attention_focus", "ap_attention_diverge", "napcat_recall_message"}
        stub_tools = {"web_search", "image_understanding", "mcp_ping", "skill_run"}
        external_reserved = {"weather", "web_search", "mcp_ping", "skill_run", "image_understanding"}
        rows: list[dict[str, Any]] = []
        counts = {"enabled": 0, "disabled": 0, "stub": 0, "mutating": 0, "readonly": 0, "external_reserved": 0}
        for tool in tools:
            name = str(tool.get("name") or "")
            enabled = bool(tool.get("enabled"))
            is_mutating = name in mutating_tools
            is_stub = name in stub_tools
            is_external_reserved = name in external_reserved
            mode = "writeback" if is_mutating else ("stub" if is_stub else ("external_readonly" if name == "weather" else "readonly"))
            if enabled:
                counts["enabled"] += 1
            else:
                counts["disabled"] += 1
            if is_stub:
                counts["stub"] += 1
            if is_mutating:
                counts["mutating"] += 1
            else:
                counts["readonly"] += 1
            if is_external_reserved:
                counts["external_reserved"] += 1
            rows.append(
                {
                    "name": name,
                    "label": tool.get("label") or name,
                    "enabled": enabled,
                    "mode": mode,
                    "writes_pa_history": False,
                    "writes_ap_runtime": is_mutating,
                    "external_call": name == "weather",
                    "stub": is_stub,
                    "external_reserved": is_external_reserved,
                    "input_schema": tool.get("input_schema") or {},
                    "description": tool.get("description") or "",
                    "safe_preview": not is_mutating,
                    "operator_note": (
                        "执行后会把工具结果回灌 AP，适合主动测试学习入口。"
                        if is_mutating
                else ("当前为占位/协议探针，不会真实访问外部服务。" if is_stub else ("会访问 Open-Meteo 免费天气 API；不需要密钥。" if name == "weather" else ("会把关键词注入 AP 并运行回忆 tick。" if name == "ap_recall" else "只读本地工具。")))
                    ),
                }
            )
        checks = [
            {
                "id": "tool_allowlist",
                "status": "pass" if self.config.tool_allowlist else "warn",
                "detail": f"allowlist={', '.join(self.config.tool_allowlist) if self.config.tool_allowlist else 'empty'}",
            },
            {
                "id": "mcp",
                "status": "warn" if self.config.mcp_enabled else "pass",
                "detail": "MCP 已开启，但当前仍是 mcp_ping 协议探针。" if self.config.mcp_enabled else "MCP 未开启；当前不会访问外部 MCP server。",
            },
            {
                "id": "skills",
                "status": "warn" if self.config.skill_enabled else "pass",
                "detail": "Skills 开关已开启；当前 skill_run 仍是状态探针。" if self.config.skill_enabled else "Skills 已关闭。",
            },
        ]
        return {
            "tools": rows,
            "counts": counts,
            "allowlist": list(self.config.tool_allowlist),
            "mcp_enabled": bool(self.config.mcp_enabled),
            "skill_enabled": bool(self.config.skill_enabled),
            "checks": checks,
            "sandbox": True,
            "generated_at_ms": _now_ms(),
            "safety_note": "本矩阵只读；真正点击“执行并回灌 AP”才会运行工具并写事件/快照。当前没有任何工具会直接发送外部消息。",
            "next_actions": [
                {"id": "mcp_registry", "label": "MCP 注册表", "detail": "后续可增加 server 列表、schema 预览、dry-run tool call。"},
                {"id": "skill_registry", "label": "Skills 注册表", "detail": "后续可把 skill_run 从状态探针扩展为受控执行器。"},
                {"id": "vision_provider", "label": "视觉模型", "detail": "配置 vision/multimodal model 后，把 image_understanding 从摘要优先升级为真实图像理解。"},
            ],
        }

